INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('An Optimized Component Selection Algorithm for Self-Adaptive Software Architecture Using the Component Repository', ' MohanRoopa Y;  Ramamohan Reddy A', 2019, '<jats:p>Component-based software engineering focuses on the development and reuse of components. The component reuse depends on the storage and retrieval processes. This article presents the component repository model for the developers to achieve good productivity. The component selection from the component repository according to the functionality and requirements is a crucial process. This article proposed an algorithm for optimizing component selection with functionality constraints like customer size, reliability, and performance. The experimental result evaluates the performance of the algorithm.</jats:p>', '10.4018/ijssci.2019040104', 'https://doi.org/10.4018/ijssci.2019040104');
