INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Dynamic Self-Adapting Software Architecture for Replica Management in Grids', 'Lei CHEN', 2006, '', '10.1360/jos171436', 'https://doi.org/10.1360/jos171436');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Architecture Uniformity', 'Fadi Sibai', 2010, '', '10.5308/2153-8409.001.01.006', 'https://doi.org/10.5308/2153-8409.001.01.006');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Quantifying software architecture quality report on the first international workshop on software architecture metrics', 'Robert L. Nord; Ipek Ozkaya; Heiko Koziolek; Paris Avgeriou', 2014, '<jats:p>Architects of complex software systems face the challenge of how best to assess the achievement of quality attributes and other key drivers, how to reveal issues and risks early, and how to make decisions about architecture improvement. Software architecture quality has a large impact on this effort, but it is usually not assessed with quantitative measures. As the pace of software delivery and technology churn increases, organizations need guidance on how to meet the business goals of their software. There is an increasing need to provide ongoing insight into the quality of the system being developed. Additionally, it is highly desirable to improve feedback between development and deployment through measurable means for intrinsic quality, value, and cost. There is increasing attention to fields such as software analytics and empirical software engineering and measurement that can provide the theory, tooling, or inspiration to develop measurement and analysis frameworks for software architecture. This paper reports on the results of the First International Workshop on Software Architecture Metrics, where participants discussed challenges and opportunities in quantifying software architecture quality.</jats:p>', '10.1145/2659118.2659140', 'https://doi.org/10.1145/2659118.2659140');
