INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Análise comparativa entre arquitetura orientada por modelos e metodologias clássicas de desenvolvimento de software', 'Paulo Vinicius Alves Melo; Mauro José Araújo de Melo', 2025, '<jats:p>This work presents a theoretical comparative analysis between Model Driven Architecture (MDA) and traditional software development methodologies, investigating technical foundations, benefits, limitations, and contextual applicability of each approach. The general objective consists of conducting a systematic comparison based on criteria established by scientific literature, identifying scenarios where each approach demonstrates superiority. The adopted methodology is characterized as qualitative descriptive-analytical theoretical research, based on bibliographic review of verifiable scientific publications. A comparative framework was established structured in technical dimensions: abstraction and model levels, documentation, software quality, traceability, maintainability, communication, automation, productivity, cost, organizational maturity, and risks. The literature review examined foundations of Waterfall, V-Model, Spiral, and RUP, as well as MDA architecture including concepts of CIM/PIM/PSM, MOF, QVT, XMI, and UML. Empirical studies revealed contradictory evidence regarding MDA productivity benefits, with effectiveness demonstrating high dependence on context, tool maturity, and domain characteristics. Traditional methodologies maintain applicability in projects with stable requirements and experienced teams. Results indicate that MDA offers advantages in separation between business logic and technology, artifact automation, and multi-platform portability, while facing challenges in learning curve, tool maturity, and representation of non-functional requirements. It is concluded that approaches do not constitute mutually exclusive alternatives, being able to coexist in hybrid strategies adapted to specific organizational contexts. </jats:p>', '10.51473/rcmos.v1i2.2025.1741', 'https://doi.org/10.51473/rcmos.v1i2.2025.1741');
