INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Software Architecture is a Set of Abstractions', 'George Fairbanks', 2023, '', '10.1109/ms.2023.3269675', 'https://doi.org/10.1109/ms.2023.3269675');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Toward Simpler, not Simplistic, Quantification of Software Architecture and Metrics', 'Ipek Ozkaya; Robert L. Nord; Heiko Koziolek; Paris Avgeriou', 2015, '<jats:p>Architects of complex software systems face the challenge of how best to assess the achievement of quality attributes and other key system drivers, how to reveal issues and risks early, and how to make decisions about architecture improvement. Software architecture quality has a large impact on this effort, but it is usually not assessed with quantitative measures. A software architecture metric quantifies architecture quality, value, and cost. While it is highly desirable to improve feedback between development and deployment through measurable means for intrinsic quality, value, and cost, efforts in software architecture quality measurement have lagged behind the body of work focusing on code quality. The goal of the Second International Workshop on Software Architecture and Metrics was to discuss progress on architecture and metrics, measurement, and analysis; to gather empirical evidence on the use and effectiveness of metrics; and to identify priorities for a research agenda.</jats:p>', '10.1145/2815021.2815037', 'https://doi.org/10.1145/2815021.2815037');
