INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('A Survey Architecture Interface and Security Issues in Software Defined Networking', '', 2018, '', '10.23883/ijrter.conf.20171225.001.qkkxb', 'https://doi.org/10.23883/ijrter.conf.20171225.001.qkkxb');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('AGILE SOFTWARE ARCHITECTURE INGLOBAL SOFTWARE DEVELOPMENT ENVIRONMENT:SYSTEMATIC LITERATURE MAPPING', 'Thiago Gomes; Marcelo Marinho', 2023, '<jats:p>In recent years, software development companies started to adopt Global Software Development (GSD) toexplore the benefits of this approach, mainly cost reduction. However, the GSD environment also brings more complexity and challenges. Some challenges are related to communication aspects like cultural differences, time zone, and language. This paper is the first step in an extensive study to understand if the software architecture can ease communication in GSD environments. We conducted a Systematic Literature Mapping (SLM) to catalog relevant studies about software architecture and GSD teams and identify potential practices for use in the software industry. This paper’s findings contribute to the GSD body of knowledge by exploring the impact of software architecture strategy on the GSD environment. It presents hypotheses regarding the relationship between software architecture and GSD challenges, which will guide future research.</jats:p>', '10.5121/ijsea.2023.14301', 'https://doi.org/10.5121/ijsea.2023.14301');
