INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('A distributed memory 1/2-approximation algorithm and heuristic for vertex-weighted matching', 'Saliyah Alotaibi; Ahmed Al-Herz', 2025, '', '10.1080/17445760.2025.2524692', 'https://doi.org/10.1080/17445760.2025.2524692');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Development and Calculation of a Computer Model and Modern Distributed Algorithms for Dispersed Systems Aggregation', 'Nurlybek Zhumatayev; Zhanat Umarova; Gani Besbayev; Almira Zholshiyeva', 2020, '<jats:p>In this work, an attempt has been made to eliminate the contradiction of the Smoluchowski equation, using modern distributed algorithms for creating calculation algorithm and implementation a program for building a more perfect model by changing the type of the kinetic equation of aggregation taking into account the relaxation times. On the basis of the applied Mathcad package, there is a developed computer model for calculating the aggregation of dispersed systems. The obtained system of differential equations of the second order is solved by the Runge-Kutt method. The authors are presetting the initial conditions of the calculation. A subsequent analysis was made of the obtained non-local equations and the study of the behavior of solutions of different orders. Also, this research can be aimed at the generalization of the proposed approach for the analysis of aggregation processes in heterogeneous dispersed systems, involving the creation of aggregation models, taking into account both time and space non-locality.</jats:p>', '10.4018/ijdst.2020040105', 'https://doi.org/10.4018/ijdst.2020040105');
