INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Rules and agents for automated management of distributed systems', 'Thomas Koch; Bernd Krä mer', 1996, '', '10.1088/0967-1846/3/2/005', 'https://doi.org/10.1088/0967-1846/3/2/005');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Spatial grasp model for dynamic distributed systems', ' ; P.S. Sapaty', 2021, '<jats:p>More complex distributed and intelligent systems which relate to economy, ecology, communi-cations, security and defense, and cover both terrestrial and celestial environments are being developed. Their efficient management, especially in dynamic and unpredictable situations, needs serious investigations and development in scientific and technological areas. Their tradi-tional representations as parts operating by certain algorithms and exchanging messages are be-coming inadequate as such systems need much stronger integration to operate as holistic organ-isms pursuing global and often varying goals. This paper is focused on a completely different paradigm for organization and management of large dynamic and distributed systems. This par-adigm extends and transforms the notion of an algorithm for the description of knowledge pro-cessing logic. Moreover, it allows it to exist, propagate and operate as an integral whole in any distributed spaces which may constantly change their volumes and structures. Taking into con-sideration some organizational features related to dangerous viruses, as well as recent pandem-ics, this ubiquitous Spatial Grasp (SG) model is presented in the paper at philosophical and im-plementation levels, together with the introduction of special spatial charts for its exhibition and studies, which extend traditional algorithmic flowcharts towards working directly in dis-tributed spaces. Utilization of this model for the creation of resultant Spatial Grasp Technology and its basic Spatial Grasp Language, already described in details in numerous publications, is briefed as well. Elementary examples of dealing with distributed networks, collective human-robotic behavior, removal of space debris by a constellation of cleaning satellites and simulat-ing the spread of virus and vaccination against it explain SG advantages over traditional system organizations.</jats:p>', '10.34121/1028-9763-2021-3-21', 'https://doi.org/10.34121/1028-9763-2021-3-21');
