INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('AI, Machine Learning &amp; Deep Learning Risk Management &amp; Controls: Beyond Deep Learning and Generative Adversarial Networks: Model Risk Management in AI, Machine Learning &amp; Deep Learning', 'Yogesh Malhotra', 2018, '', '10.2139/ssrn.3193693', 'https://doi.org/10.2139/ssrn.3193693');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Chinese Teaching and Learning Model Based on Deep Learning', 'Yipu Wang; Stuart Perrin', 2024, '<jats:p>Deep learning is a more situational and reflective way of learning that integrates complex knowledge and skills into intuitive thinking. As a language that closely combines sound, form and meaning, Chinese teaching and learning from the perspective of deep learning can help break through the limitations of the current teaching model that only focuses on certain language knowledge or cultural behaviors. This paper combines deep learning with international Chinese education, creates deep Chinese teaching and learning model including “four stages and ten steps”, and carries out practical application and teaching effect test. The results show that the deep Chinese teaching and learning model is conducive to improving students’ discourse presentation ability and comprehensive skills, cultivating the learners’ autonomous learning ability and intercultural communication competence, and strengthening the integration of language teaching and cultural teaching. At the same time, this model also has some limitations, need to be further adjusted and optimized.</jats:p>', '10.18178/ijlll.2024.10.1.479', 'https://doi.org/10.18178/ijlll.2024.10.1.479');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Performance Analysis of Extensional Deep Learning And Boosted Intensional Deep Learning Method', '', 2023, '', '10.48047/nq.2022.20.3.nq22955', 'https://doi.org/10.48047/nq.2022.20.3.nq22955');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep learning? What deep learning?', 'C. M. Fourie', 2011, '', '10.4314/sajhe.v17i1.25201', 'https://doi.org/10.4314/sajhe.v17i1.25201');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Learning Innovation in Global Citizenship Education by Integrating Deep Learning Approach', 'Sutrisno Sutrisno; Sunarto Sunarto; Dyah Mustikasari', 2026, '<jats:p>Conventional learning methods in dealing with the complexity of dynamic and multidimensional global issues in learning global citizenship education are still ineffective, this can be seen from the low understanding and awareness of students in solving global issues that occur. This research aims to develop and test learning innovations by integrating deep learning approaches to improve students'' understanding and participation in the context of global citizenship. The research method used was quantitative research with an experimental approach. The research subjects consisted of senior high school students in a sample school. The research instruments included questionnaires, comprehension tests, and observations used to measure the effectiveness of learning before and after the application of the deep learning approach. The collected data were analyzed using descriptive and inferential statistics to assess the improvement of learning outcomes. The results showed that the integration of deep learning approach in global citizenship education significantly improved students'' concept understanding, critical thinking skills, and learning motivation. Students become more active and able to connect civic education materials with contemporary global issues more deeply. The implication of this research finding is that the application of deep learning technology can be an effective innovative strategy in developing global citizenship education that is adaptive and responsive to the challenges of the times. This encourages educators to utilize artificial intelligence technology in the learning process to create a more interactive and meaningful learning experience.</jats:p>', '10.23917/jdl.v1i2.11224', 'https://doi.org/10.23917/jdl.v1i2.11224');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Reinforcement Learning: An Innovative Approach that Combines Deep Learning and Reinforcement Learning', 'Yan Cui', 2026, '<jats:p>Deep reinforcement learning (DRL) has emerged as a transformative paradigm that integrates the powerful representation-learning capabilities of deep neural networks with the sequential decision-making framework of reinforcement learning. Building upon the foundations of value functions, policy optimization, and Markov decision processes, DRL enables agents to operate effectively in high-dimensional, nonlinear, and dynamic environments where traditional methods fall short. This article provides a comprehensive overview of the theoretical principles, core algorithms, and key enabling techniques—such as neural network architectures, experience replay, Deep Q-Networks, and policy-gradient approaches—that underpin modern DRL systems. In addition, the paper examines several prominent application domains, including gaming, robotics, autonomous driving, finance, and healthcare, highlighting how DRL facilitates adaptive control, long-term optimization, and human-centered interaction. Challenges such as sample inefficiency, limited interpretability, and safety concerns are discussed, alongside emerging directions including model-based RL, multimodal learning, transfer learning, and ethical considerations. Overall, this study underscores the substantial potential of deep reinforcement learning to advance artificial intelligence and provides insights into future research necessary to ensure reliable, efficient, and responsible deployment of DRL technologies.</jats:p>', '10.56028/aetr.16.1.500.2026', 'https://doi.org/10.56028/aetr.16.1.500.2026');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Improving Student Learning Outcomes in Fiqh Learning through the Student Problem Based Learning Model at MI Nurul Jihad', ' Muzanni;  Najla', 2025, '<jats:p>This study aims to improve the learning motivation of fifth grade students of MI Nurul Jihad in the subject of Fiqh through the application of the Problem Based Learning learning model. The background of the study identified that the learning process tends to focus on memorization, does not involve students actively, and results in low learning motivation. This condition is influenced by limited facilities and infrastructure, lack of mastery of science and technology by teachers, and low student interest in learning. Based on these problems, this classroom action research was formulated to answer the question: "Can the use of the Problem Based Learning learning model improve students'' learning motivation in the field of Fiqh studies of fifth grade MI Nurul Jihad?" This study uses the Classroom Action Research method that focuses on the implementation of the Problem Based Learning model. Data were collected through tests, observations, and documentation, then analyzed descriptively qualitatively. The results of initial observations showed low student participation and learning outcomes, where only 66.7% of students (10 out of 15) achieved completion with an average score of 65.33. After implementing cycle I of the PBL model, there was a significant increase in student learning outcomes, with 80.0% of students (12 out of 15) achieving completion and the class average score increasing to 75.0.</jats:p>', '10.62945/deeplearning.v1i1.211', 'https://doi.org/10.62945/deeplearning.v1i1.211');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Distraction Detection for Vehicle Drivers Using Deep Learning Techniques: A Review of Advanced Deep Learning Techniques', 'Yash Pansare; Lav Parab; Atharva Patil', 2025, '', '10.55248/gengpi.6.0425.16118', 'https://doi.org/10.55248/gengpi.6.0425.16118');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('OBJECT RECOGNITION WITH DEEP LEARNING AND MACHINE LEARNING METHODS', 'İsmail Akgül; Yıldız Aydın', 2022, '', '10.12739/nwsa.2022.17.4.2a0189', 'https://doi.org/10.12739/nwsa.2022.17.4.2a0189');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('From machine learning to deep learning: experimental comparison of machine learning and deep learning for skin cancer image segmentation', 'Ranpreet Kaur', 2022, '<jats:p>Skin lesion analysis is a tedious and challenging task, thus, in this research the suitability of employing machine learning or deep learning approaches for automatic lesion segmentation on dermoscopic skin cancer images is determined. The segmented region can assist clinical experts in understanding the complex lesion structure and internal pattern to find the correct skin cancer type for its early diagnosis and prevention. In this study, I present two methodologies for performing lesion segmentation: machine learning-based optimized K-means with Firefly Algorithm (FA) and Convolutional Neural Network (CNN). In the first model, the FA is hybridized with K-means clustering based on the novel average intensity fitness function to optimize the segmentation map. It is observed in the experimental results that the K-means algorithm may lead to poor results due to the wrong selection of initial centroid value, thus FA is hybridized into it to improve the performance. The second model is an enhanced encoder-decoder-based CNN framework implemented in an end-to-end fashion. These two models are compared to understand whether machine learning or deep learning is suitable to perform medical image segmentation based on a few performance metrics such as accuracy, Intersection over Union (IoU), and DICE index. These methods are evaluated and compared on two benchmark datasets provided by the International Skin Imaging Collaboration (ISIC) named ISIC 2016 [1] and ISIC 2017 [2]. Experimental results showed that the CNN model outperformed the machine learning model with an accuracy difference of 7.98% on ISIC 2016, and 7.32% on ISIC 2017. I concluded from the experimental findings that the deep learning model is more accurate and efficient in segmenting the lesion area as compared to the machine learning model. Thus, findings from this experimental work will be considered for the design of an automatic classification system by incorporating a deep learning-based segmentation approach as a pre-processing step. </jats:p>', '10.24135/rangahau-aranga.v1i1.32', 'https://doi.org/10.24135/rangahau-aranga.v1i1.32');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning-Based Learning Strategies in Realizing Meaningful, Critical, and Enjoyable Learning', 'Rizwatul Hasanah; Harun Joko Prayitno; Suni Tuti; Sarilan Sarilan; Velandani Prakoso', 2026, '<jats:p>This study aims to examine the form and scope of the application of Deep Learning in the Vocational High School (SMK), especially at SMK Mantingan, through a literature study approach. Deep Learning, as part of artificial intelligence, has great potential in the world of vocational education, especially in supporting technology-based learning and improving student competencies in the digital field. This study relies on various literature sources such as scientific journals, books, articles, and relevant documents to examine the concepts, applications, and challenges faced in the integration  of Deep Learning in vocational schools. The results of the study show that although the application  of Deep Learning in vocational schools, including at SMK Mantingan, is still relatively new and limited, there are great opportunities for development in project-based learning and improving students'' digital literacy. The scope of implementation includes the introduction of basic concepts, the use of supporting software, and the use of simple models for educational purposes. This study recommends the need for teacher training, the provision of adequate infrastructure, and collaboration with higher education institutions or industry to expand the application of this technology in vocational schools.</jats:p>', '10.23917/jdl.v1i2.11572', 'https://doi.org/10.23917/jdl.v1i2.11572');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Down the deep rabbit hole: Untangling deep learning from machine learning and artificial intelligence', 'Niel Chah', 2019, '<jats:p>Interest in deep learning, machine learning, and artificial intelligence from industry and the general public has reached a fever pitch recently. However, these terms are frequently misused, confused, and conflated. This paper serves as a non-technical guide for those interested in a high-level understanding of these increasingly influential notions by exploring briefly the historical context of deep learning, its public presence, and growing concerns over the limitations of these techniques. As a first step, artificial intelligence and machine learning are defined. Next, an overview of the historical background of deep learning reveals its wide scope and deep roots. A case study of a major deep learning implementation is presented in order to analyze public perceptions shaped by companies focused on technology. Finally, a review of deep learning limitations illustrates systemic vulnerabilities and a growing sense of concern over these systems.</jats:p>', '10.5210/fm.v24i2.8237', 'https://doi.org/10.5210/fm.v24i2.8237');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Seeing Deep into the Lungs with Deep Learning', 'Yiqiao Yin', 2022, '', '10.33548/scientia849', 'https://doi.org/10.33548/scientia849');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Conscious Learning Model in Improving Students'' Learning Outcomes: A Classroom Action Research at MIN 5 Bone', ' Ferdiansyah;  Nahirah', 2025, '<jats:p>In the learning process, there are still many teachers who use the direct learning model with the lecture method, this makes students bored and bored during the learning process, so teachers need to vary the fun learning model according to learning so that students do not feel bored and bored. This study aims to examine the implementation of the Conscious Learning Model in improving students'' learning outcomes through Classroom Action Research (CAR). The Conscious Learning Model emphasizes active student engagement, awareness in learning processes, and metacognitive strategies that enable learners to understand not only what they learn but how they learn. The research was conducted in two cycles, each consisting of planning, action, observation, and reflection stages. The subjects of this study were students from a fifth-grade class at a public elementary school in Indonesia. Data were collected through observation, tests, and documentation to measure changes in student learning outcomes and engagement. The results indicated a significant improvement in student learning outcomes after the implementation of the Conscious Learning Model. In the first cycle, students showed moderate improvement, with several still struggling to articulate learning goals and monitor their understanding. In the second cycle, however, there was a marked increase in students'' ability to plan, evaluate, and regulate their learning processes. This was evidenced by higher test scores, increased participation in classroom discussions, and more reflective learning behaviors. The study concludes that the Conscious Learning Model is an effective approach to enhance student learning outcomes, particularly when applied consistently with supportive instructional strategies and reflective teaching practices. The implications of this research suggest that integrating conscious and reflective learning activities into daily instruction can foster more meaningful and self-directed learning experiences for students.</jats:p>', '10.62945/deeplearning.v1i2.221', 'https://doi.org/10.62945/deeplearning.v1i2.221');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Small Group Discussion Strategies Reviewed to Improve Student Learning Outcomes in Civics Learning at MI Sultan Agung', 'Wahyu Rustyaningsih', 2025, '<jats:p>This study aims to examine the effectiveness of small group learning strategies in improving student learning outcomes in Civics Education at MI Sultan Agung. Civics, as a subject, plays a crucial role in shaping students'' character, sense of responsibility, and awareness of democratic values. However, traditional teaching methods often result in passive student participation and low academic performance. To address this issue, this research implemented a classroom action research (CAR) approach consisting of two cycles, each comprising planning, action, observation, and reflection. The subjects of the study were fifth-grade students at MI Sultan Agung, totaling 28 participants. Data collection techniques included observation, tests, and documentation. The findings indicate a significant improvement in student learning outcomes after applying small group learning strategies. In the first cycle, the average student learning outcome reached 68.21, with 60.71% of students achieving the minimum mastery criterion (MMC). In the second cycle, the average score increased to 82.14, with 89.29% of students achieving the MMC. Furthermore, student engagement and participation in the learning process showed marked improvement, indicating that small group strategies promote collaboration, active learning, and critical thinking. These results support the conclusion that small group learning is an effective pedagogical approach for enhancing both cognitive and affective learning outcomes in Civics Education. This study contributes to the growing body of research advocating for student-centered learning environments and highlights the importance of interactive teaching methods in primary education. The implementation of small group learning is recommended as a sustainable strategy to improve educational quality, particularly in the context of civic education, where active student involvement is essential. Future research may explore the long-term impact of this strategy and its application across different subjects and educational settings.</jats:p>', '10.62945/deeplearning.v1i1.202', 'https://doi.org/10.62945/deeplearning.v1i1.202');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Questionable Practices in Methodological Deep Learning Research', 'Daniel J. Trosten', 2023, '<jats:p>Evaluation of new methodology in deep learning (DL) research is typically done by reporting point estimates of a few performance metrics, calculated from a single training run. This paper argues that this frequently used evaluation protocol in DL is fundamentally flawed -- presenting 8 questionable practices that are widely adopted in the evaluation of new DL methods. The questionable practices are derived from violations of statistical principles of the scientific method, and from Hansson''s definition of pseudoscience. A survey of recent publications from a top-tier DL conference indicates the widespread adoption of these practices in state-of-the-art DL research. Lastly, arguments in favor of the questionable practices, possible reasons for their adoption, and measures that have been taken to remove them, are discussed.</jats:p>', '10.7557/18.6804', 'https://doi.org/10.7557/18.6804');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Implementation of Problem Based Learning Model to Improve Learning Outcomes at SD Negeri Lawe Bulan', 'Irma Fitri Suriani', 2025, '<jats:p>This classroom action research aims to improve the learning outcomes of fourth-grade students at SD Negeri Lawe Bulan in the topic of "Approaching Puberty" through the implementation of the Problem Based Learning (PBL) model. The study is motivated by the low academic performance observed in students, which fell below the Minimum Competency Standard. The conventional and monotonous learning methods were identified as contributing factors to students’ lack of engagement and understanding, particularly in Islamic religious education, where concepts are often delivered as rote memorization. The research was conducted in two cycles, each consisting of planning, action, observation, and reflection. Data collection techniques included tests, observations, and documentation. The findings indicate that PBL significantly enhanced students'' critical thinking, engagement, and learning outcomes. In Cycle I, the average student score was 77.92, while in Cycle II, it increased to 86.28. Student and teacher activities during learning also improved from "good" to "very good" qualifications. The PBL model, by incorporating real-life problems and collaborative learning, created a more meaningful learning experience and promoted students’ active participation. This approach helped students better understand the physical and emotional changes associated with puberty and encouraged them to take responsibility for their learning. The results of this study demonstrate that PBL is an effective instructional model to foster deeper comprehension, critical thinking skills, and improved academic performance in religious education. It also supports the development of independent, creative, and responsible learners.</jats:p>', '10.62945/deeplearning.v1i2.223', 'https://doi.org/10.62945/deeplearning.v1i2.223');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning vs Differentiated Learning: Learning Innovation in Islamic Boarding School-Based Middle Schools', 'Murwanto Setyo Nugroho; Harun Joko Prayitno; Koesoemo Ratih; Muhammad Samsudin', 2026, '<jats:p>This study aims to examine the implementation of deep learning and differentiated learning approaches in Islamic boarding school-based junior high schools (SMP) in order to improve the quality of meaningful, contextual, and humanistic learning. Using a descriptive qualitative approach, data were collected through in-depth interviews, classroom observations, and documentation studies in three Islamic boarding school junior high schools that integrate national and religious curricula. The results of the study indicate that learning strategies such as project-based learning, reflective discussions, and collaborative activities are effective in building conceptual understanding and spiritual values ​​of students. Differentiated learning enables the creation of an inclusive learning environment by adjusting content, processes, and products according to students'' learning profiles. Implementation challenges arise in terms of time constraints, dual curriculum burdens, and teacher professional readiness. Authentic project-based and portfolio-based evaluations are more relevant in measuring cognitive, affective, and spiritual competencies holistically. This study recommends the need for educational policies that are more adaptive to the characteristics of Islamic boarding schools, including contextual teacher training, curriculum flexibility, and an inclusive and sustainable evaluation system. These findings confirm that deep learning and differentiated learning have great potential in transforming Islamic boarding school education towards 21st-century learning that is more humanistic, reflective, and transformative.</jats:p>', '10.23917/jdl.v1i1.11246', 'https://doi.org/10.23917/jdl.v1i1.11246');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Improving Student Learning Motivation in Islamic Education Learning Using an Activity-Based Approach at SD Negeri Inpres Baralau', 'Sri Ernawati', 2025, '<jats:p>This study investigates the effectiveness of an activity-based approach in enhancing students'' learning motivation in Islamic Education at SD Negeri Inpres Baralau. Learning motivation is a critical factor that significantly influences students’ academic success, particularly in religious education where engagement can be challenging due to traditional and passive instructional methods. The research employed a classroom action research design conducted in two cycles, each consisting of planning, implementation, observation, and reflection stages. Data were collected through observation sheets, student questionnaires, and teacher interviews to triangulate findings. The participants involved were 32 students in Grade V during the 2024/2025 academic year. The findings revealed a marked improvement in students’ motivation following the implementation of activity-based learning strategies, including group discussions, role-playing, games, and creative project assignments related to Islamic values. Quantitative data showed a significant increase in students’ motivation scores, rising from an average of 62.3 in the pre-cycle to 76.8 in the first cycle and 85.4 in the second cycle. Qualitative observations supported these results, indicating higher levels of enthusiasm, participation, and sustained attention during lessons. This research highlights that integrating interactive and student-centered learning activities into Islamic Education can foster a more engaging and motivating learning environment. The study recommends adopting activity-based approaches in primary religious education to cultivate not only students’ interest but also a deeper understanding and internalization of Islamic values. These findings are relevant for educators, policymakers, and curriculum developers aiming to improve educational practices in faith-based learning contexts. Future research may explore the long-term impact of such approaches across different educational levels and cultural settings.</jats:p>', '10.62945/deeplearning.v1i1.196', 'https://doi.org/10.62945/deeplearning.v1i1.196');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Cooperative Learning Strategy to Improve Student Learning Outcomes on the Theme of Always Saving Energy at MI Nurul Ihsan', ' Haryati', 2025, '<jats:p>This study investigates the effectiveness of domino card media in improving science learning outcomes for students at MIS Mawu. Recognizing the limitations of traditional, passive learning methods in fostering deep understanding and engagement in science, this research explores the potential of an interactive and collaborative learning tool. Domino cards, designed to connect various scientific concepts, terms, or processes, were implemented as a pedagogical intervention. The study examines the impact of this medium on student engagement, collaborative learning skills, critical thinking abilities, and ultimately, their academic achievement in Ilmu Pengetahuan Alam (Natural Science). Data was collected through [mention data collection methods if specified in a full paper, e.g., pre- and post-tests, observations, student feedback]. The findings of this research aim to provide empirical evidence on the efficacy of domino card media as a tool for enhancing science education in the specific context of MIS Mawu. The results of this study [mention key findings if specified in a full paper, e.g., demonstrated a statistically significant improvement in student test scores, increased student engagement during lessons, enhanced collaborative problem-solving skills]. These findings suggest that the application of domino card media offers a valuable and engaging approach to teaching science, promoting active learning, collaboration, and critical thinking among students at MIS Mawu. The interactive and visual nature of the domino cards facilitated a deeper understanding of interconnected scientific concepts and catered to diverse learning styles. This research contributes to the growing body of literature on innovative teaching methodologies in science education and provides practical insights for educators seeking to enhance student learning outcomes through the use of engaging and hands-on media.</jats:p>', '10.62945/deeplearning.v1i1.208', 'https://doi.org/10.62945/deeplearning.v1i1.208');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('The Use of Domino Card Media to Improve Student Learning Outcomes in Natural Science Learning at MIS Mawu', ' Nurmalah;  Juhraeni', 2025, '<jats:p>The results of students'' science learning are still very low when viewed from the results of daily tests that have been held four times, namely the average is 6.45, this means that it has not met the KKM for science subjects, which is 6.7. The factors causing low student learning outcomes are the teaching methods applied by teachers tend not to activate students, teachers never use media during learning so that students are not interested and not motivated to participate in learning. To solve the above problems, researchers use domino card media in learning. This study aims to determine the impact of using domino card media on improving the science learning outcomes of class III students of MIS Mawu, Ambalawi District, Bima Regency in the 2022/2023 academic year. The method used in this study is classroom action research. PTK is action research carried out with the aim of improving the quality of learning practices in the classroom. The subjects in this study were 39 class III students of MIS Mawu. The type of data used in this study is quantitative data. Where quantitative data is data obtained from student learning outcome data for each evaluation. Data was collected using a learning outcome test. The results of the study showed that the average student learning outcomes in cycle I were 65.00 and had not met the KKM for science subjects and in cycle II the average student learning outcomes increased to 75.12 and had met the KKM for science subjects. Thus, it can be concluded that the use of domino card media can improve the science learning outcomes of class III students of MIS Mawu, Ambalawi District, Bima Regency in the 2022/2023 academic year.</jats:p>', '10.62945/deeplearning.v1i1.209', 'https://doi.org/10.62945/deeplearning.v1i1.209');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('RIDDLE: Rule Induction with Deep Learning', 'Cosimo Persia; Ricardo Guimarães', 2023, '<jats:p>Numerous applications rely on the efficiency of Deep Learning models to address complex classification tasks for critical decisions-making. However, we may not know how each feature in these models contributes towards the prediction. In contrast, Rule Induction algorithms provide an interpretable way to extract patterns from data, but traditional approaches suffer in terms of scalability. In this work, we bridge Deep Learning and Rule Induction and define the RIDDLE (Rule Induction with Deep Learning) architecture. We show that RIDDLE has state-of-the-art performance in Rule Induction via an empirical evaluation.</jats:p>', '10.7557/18.6801', 'https://doi.org/10.7557/18.6801');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning in diverse Computing and Network Applications Student Admission Predictor using Deep Learning', 'P. Nandal', 2020, '', '10.2139/ssrn.3562976', 'https://doi.org/10.2139/ssrn.3562976');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Designing Mathematics Teaching through Deep Learning Pedagogy: Toward Meaningful, Mindful, and Joyful Learning', 'Torang Siregar; Ahmad Fauzan; Yerizon Yerizon; Syafriandi Syafriandi', 2026, '<jats:p>Mathematics education in the 21st century requires an approach that focuses not only on procedural mastery but also on deep conceptual understanding, critical thinking skills, and the ability to transfer knowledge across various life contexts. This article discusses the design of mathematics learning based on a deep learning approach not in the context of artificial intelligence, but as a pedagogical approach integrating three core principles: meaningful, mindful, and joyful. Meaningful learning is built through contextual activities and open-ended problems that connect mathematical concepts to real-world situations. Reflective and process-aware learning is facilitated through discussion, metacognitive reflection, and evaluation. Meanwhile, a joyful learning environment is created through active participation, open exploration, and recognition of diverse student thinking styles. The theoretical framework includes constructivism, transfer theory, metacognition, and process-based assessment. The implementation of this approach requires a transformation of the teacher''s role into a facilitator, a flexible and meaning-oriented curriculum, and a supportive, collaborative learning environment. It is concluded that the deep learning approach, through the principles of meaningful, mindful, and joyful learning, can enhance student engagement, deepen understanding, and foster a positive attitude toward mathematics.</jats:p>', '10.23917/jdl.v1i2.11969', 'https://doi.org/10.23917/jdl.v1i2.11969');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Machine Learning and Deep Learning Approaches for Cybersecurity: A Review', 'Migul Jain', 2023, '', '10.21275/sr231023115126', 'https://doi.org/10.21275/sr231023115126');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('"Deep Non-Parametic Learning Architecture:  Performance Analysis Of Deep Learning  Architecture"', '', 2023, '', '10.56452/7-4-243', 'https://doi.org/10.56452/7-4-243');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Forecasting Thai Agricultural Price: A Deep Learning Approach for Key Commodities', '', 2026, '', '10.18178/ijml.2026.16.1.1185', 'https://doi.org/10.18178/ijml.2026.16.1.1185');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Straight Forward Constructive Deep Learning Neural Network (SFC-DLNN) Algorithm', '', 2022, '<jats:p>Straight Forward Constructive Deep Learning Neural Network (SFC-DLNN) algorithm is a new architecturebased algorithm for artificial neural networks. Rather than simply adjusting the weights in a fixed topology network, SFC-DLNN starts with a minimal topology (perceptron), then builds up their network by gradually trains and adds new nodes one by one, creating multiple layers’ network. Once a unit has been added to the network, the weights of the new architecture are generated. This unit then stands as a permanent detector of features in the network, and a more complex feature space is then created where the data is likely to be linearly separable. The SFC-DLNN algorithm has many advantages over existing ones: it has good learning speed, the network determines its topology size, and the structures it has built is retained after the training stage. We obtain from our built model (SFC-DLNN) an accuracy and specificity of 83:5% from a simulated data set using the uniform distribution. This is not the best but is enough to approve the model prediction capacity</jats:p>', '10.33140/amlai.03.02.04', 'https://doi.org/10.33140/amlai.03.02.04');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning –An Overview', '', 2019, '', '10.36266/jcet/104', 'https://doi.org/10.36266/jcet/104');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('FEATURE SELECTION AND DEEP LEARNING MODEL FOR AIR QUALITY PREDICTION', 'Agastya Shrivastava', 2025, '', '10.34218/ijaidl_02_02_001', 'https://doi.org/10.34218/ijaidl_02_02_001');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Uncertainty Estimation in Deep Learning: Methods and Applications', 'Hina Batool; Tahir Abbas; Jamshaid Iqbal Janjua; Sadaqat Ali Ramay', 2025, '<jats:p>Uncertainty estimation in deep learning has emerged as a crucial area of research due to its significance in enhancing model reliability and decision-making in critical applications. This article explores various methods and applications of uncertainty estimation in deep learning, aiming to provide insights into its importance, methods, and potential impact. Through a comprehensive literature review and analysis, the study identifies key findings regarding the effectiveness, limitations, and ethical considerations associated with uncertainty estimation techniques. The results reveal the diverse range of methodologies employed, including Bayesian approaches, ensemble methods, and Monte Carlo sampling, each with its strengths and drawbacks. Furthermore, the article discusses the implications of uncertainty estimation in deep learning for fields such as healthcare, autonomous systems, and safety-critical domains. Overall, this study underscores the significance of uncertainty estimation in deep learning and provides valuable insights for researchers and practitioners in the field.</jats:p>', '10.64820/aepjmldl.11.41.46.122024', 'https://doi.org/10.64820/aepjmldl.11.41.46.122024');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Improving Understanding and Attitude of Gratitude Using Project Based Learning Model in Islamic Education Learning at SMP Negeri 1 Barumun Baru', 'Hayatunnisah Nst', 2025, '<jats:p>This study aims to improve student learning outcomes in Islamic religious education learning using Project Based Learning. This study is a classroom action research that uses four steps, namely planning, action, observation and reflection. The subjects of this study were junior high school students. The data for this study were obtained using test and observation techniques. Tests are used to measure learning outcomes and observations are used to analyze teacher and student learning activities. The data analysis technique used in this study is descriptive statistics by comparing the results obtained with indicators of research success. The results of the study indicate that Project Based Learning can improve student learning outcomes in Islamic religious education learning. This can be seen from the increase in the percentage of student learning completion in each cycle with details of the pre-cycle 48.71%, the first cycle 65.39% and in the second cycle it increased to 89.76%. Thus, the use of Project Based Learning can be used as an alternative to improve student learning outcomes in Islamic religious education learning.</jats:p>', '10.62945/deeplearning.v1i1.205', 'https://doi.org/10.62945/deeplearning.v1i1.205');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Spectral Deep Learning in Chronic Pulmonary Thromboembolism', 'Henrique J Cirino', 2024, '<jats:p>Pulmonary scintigraphy is considered a technique of choice in the evaluation of chronic pulmonary thromboembolism. Technical advancements in computed tomography as dual-energy (spectral) have allowed obtaining high quality images. As an example, a computed tomography as dual-energy patient case is shown, who underwent both scintigraphy and spectral deep learning not only was a lower radiation dose observed scintigraphy but also provided anatomical data on perfusion defect, essential for surgical planning and also evidenced other areas of perfusion alteration that were not clearly identified on V/Q scintigraphy. Thus, we bring this initial experience with the use of Spectral Deep Learning as a possibility to combine anatomical and perfusional assessment in the same acquisition, reducing dose and possible costs</jats:p>', '10.53902/atr.2024.02.000502', 'https://doi.org/10.53902/atr.2024.02.000502');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Artificial Intelligence in Cybersecurity: Machine Learning and Deep Learning for Intelligent Threat Detection', 'Rita Dewanjee', 2026, '', '10.21275/sr26221124055', 'https://doi.org/10.21275/sr26221124055');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning Approach: Potentials and Challenges in Indonesian Education', 'Izza Hanifa Astono; Sri Endah Wahyuningsih; Sri Handayani', 2026, '<jats:p>The transformation of education in the era of globalization and the Industrial Revolution 4.0 requires a paradigm shift from memorization-based learning toward approaches that emphasize deep understanding, active engagement, and the development of twenty-first century skills. The Deep Learning approach has emerged as a relevant pedagogical strategy to address these challenges in both academic and vocational education contexts. This study aims to comprehensively review the conceptual foundations, theoretical frameworks, empirical effectiveness, and the role of technology in implementing Deep Learning within Indonesia’s educational ecosystem. This research employs a literature review method by examining a range of scholarly articles and relevant policy documents, with a focus on deep learning practices, higher-order thinking development, and the integration of educational technologies. The findings indicate that the Deep Learning approach is supported by robust theoretical frameworks, such as the Deep Mathematical Thinking (DMT) model, which emphasizes conceptual connectivity, intrinsic motivation, and metacognition. Empirical evidence further demonstrates that the implementation of Deep Learning significantly enhances learning outcomes, cognitive engagement, and students’ conceptual understanding. Within vocational education, the integration of simulation technologies under the frameworks of Deep Learning and Joyful Learning has been shown to substantially improve students’ practical competencies and the overall quality of learning experiences. This study concludes that the integration of strong theoretical foundations, Deep Learning pedagogy, and adaptive learning technologies constitutes a key driver of effective and sustainable educational reform, aligned with global demands and future-oriented educational transformation.</jats:p>', '10.23917/jdl.v2i1.14135', 'https://doi.org/10.23917/jdl.v2i1.14135');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Plant disease detection using Machine learning and Deep learning', 'Likhith Simhadri', 2025, '', '10.55248/gengpi.06.1125.38111', 'https://doi.org/10.55248/gengpi.06.1125.38111');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('The Use of Audio Visual Media in Improving Student Learning Outcomes in Islamic Education Learning at SD Negeri 6 Bandar Baru', 'Linda Nelsiani;  Fauziah', 2025, '<jats:p>This Classroom Action Research (CAR) investigates the effectiveness of audio-visual media in improving student learning outcomes in Islamic Education, specifically focusing on the attributes of the prophets, at SD Negeri 6 Bandar Baru. Recognizing the potential of multi-sensory learning experiences to enhance student engagement and comprehension, this study implemented audio-visual media as an instructional tool. The research followed a cyclical PTK model, involving planning, action, observation, and reflection. Data on student learning outcomes was collected through pre-tests and post-tests administered before and after the implementation of audio-visual media, while student engagement was observed and documented during the learning process. The study aimed to determine whether the integration of audio-visual media could lead to a significant improvement in students'' understanding and retention of the material on the attributes of the prophets, as well as foster a more conducive and engaging learning environment. The findings of this research demonstrated a positive impact of audio-visual media on student learning outcomes in Islamic Education concerning the attributes of the prophets at SD Negeri 6 Bandar Baru. A comparison of pre-test and post-test scores revealed a statistically significant improvement in students'' understanding of the material. Furthermore, observations indicated increased student engagement, participation, and enthusiasm during lessons that incorporated audio-visual aids. The interactive and multi-sensory nature of the media appeared to facilitate better comprehension and retention of complex concepts. These results suggest that the strategic application of audio-visual media can be a valuable pedagogical approach for enhancing learning outcomes in Islamic Education, particularly for abstract topics like the attributes of the prophets, and warrants further exploration and implementation in similar educational settings.</jats:p>', '10.62945/deeplearning.v1i1.214', 'https://doi.org/10.62945/deeplearning.v1i1.214');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Improving Student Learning Achievement through Group Guidance in Natural and Social Sciences Subjects at MI Maraqitta''limat Lengkok Lendang', ' Harsini', 2025, '<jats:p>This study aims to investigate the effectiveness of group counseling in improving student achievement in the subject of Natural and Social Sciences at MI Maraqitta’limat Lengkok Lendang. The research is grounded in the growing need for innovative educational approaches that address not only academic content but also students’ motivation, collaboration skills, and personal development. Utilizing a classroom action research (CAR) method, the study was conducted in two cycles, each consisting of planning, action, observation, and reflection stages. The subjects were fifth-grade students who demonstrated low academic performance and limited participation in classroom activities. Data collection methods included tests, observations, field notes, and student interviews. The results indicate a significant improvement in student learning outcomes after the implementation of group counseling. In Cycle I, only 56% of students reached the minimum competency standard, whereas in Cycle II, this number increased to 87%. Furthermore, qualitative data revealed an increase in students’ motivation, self-confidence, and ability to work cooperatively with peers. The findings suggest that group counseling is an effective strategy to enhance not only academic achievement but also affective and social aspects of learning. Therefore, it is recommended that educators consider incorporating group counseling techniques into their teaching practices, especially in subjects that require critical thinking and interpersonal skills. This research contributes to the broader discourse on holistic education and offers practical implications for teachers, school counselors, and educational policymakers aiming to foster inclusive and supportive learning environments.</jats:p>', '10.62945/deeplearning.v1i1.197', 'https://doi.org/10.62945/deeplearning.v1i1.197');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Penerapan Problem Based Learning Terintegrasi Deep Learning untuk Meningkatkan Motivasi Belajar Siswa', 'Rifninda Nur Linasari; Ana Fitrotun Nisa', 2026, '<jats:p>Penelitian ini bertujuan untuk menganalisis peningkatan motivasi belajar IPAS siswa kelas V di SD Negeri Jetisjogopaten Tahun Ajaran 2024/2025 setelah diterapkannya model pembelajaran Problem Based Learning terintegrasi pendekatan Deep Learning. Jenis penelitian ini adalah Penelitian Tindakan Kelas (PTK) dengan subjek penelitian adalah siswa kelas V yang berjumlah 20 orang siswa. Data motivasi belajar IPAS siswa dikumpulkan melalui angket. Data yang diperoleh dianalisis menggunakan analisis statistik deskriptif. Berdasarkan hasil analisis data, pada siklus I rerata motivasi belajar IPAS siswa kelas V di SD Negeri Jetisjogopaten setelah mengikuti pembelajaran dengan menerapkan model pembelajaran Problem Based Learning terintegrasi Deep Learning sebesar 77,82 dan berada pada kategori sedang. Persentase ketuntasan klasikalnya adalah 72,46%. Pada siklus II rerata motivasi belajar IPAS siswa kelas V di SD Negeri Jetisjogopaten setelah mengikuti pembelajaran dengan menerapkan model pembelajaran Problem Based Learning meningkat yakni menjadi 83,45 dan berada pada kategori tinggi. Persentase ketuntasan klasikalnya adalah 87,64%. Berdasarkan hasil tersebut dapat disimpulkan bahwa model pembelajaran Problem Based Learning terintegrasi pendekatan Deep Learning secara efektif mampu meningkatkan motivasi belajar IPAS siswa.</jats:p>', '10.23887/jpp.v58i3.95456', 'https://doi.org/10.23887/jpp.v58i3.95456');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('COMBINAÇÃO DE DEEP LEARNING E MACHINE LEARNING PARA DIAGNÓSTICO AUXILIADO POR INTELIGÊNCIA ARTIFICIAL', 'Fábio Lofredo Cesar; Hygor Santiago Lara', 2025, '<jats:p>Este trabalho propõe um sistema híbrido que combina a ResNet (Residual Network - amplamente reconhecida por seu impacto no aprendizado profundo, sendo um marco na área de visão computacional) com Árvores Extremamente Aleatórias (Extra Trees) para classificar imagens de raio-X de tórax e auxiliar na detecção de doenças. A abordagem utiliza a técnica de Transfer Learning, onde a ResNet, previamente treinada, é empregada para extrair características relevantes das imagens. Em seguida, o algoritmo Extra Trees realiza a classificação com base nessas características. Na etapa inicial, utilizando apenas a ResNet combinada com uma pequena rede neural, obtivemos uma acurácia de 95,40% na validação e 79,33% nos testes. Com a implementação do sistema híbrido, os resultados foram significativamente aprimorados, alcançando 96,90% de acurácia na validação e 89,98% nos testes, representando uma melhoria expressiva de aproximadamente 10 pontos percentuais nos testes. Esses resultados destacam o potencial do sistema híbrido em aplicações, demonstrando como a combinação de técnicas avançadas de aprendizado profundo e aprendizado de máquina pode contribuir significativamente para a melhoria da precisão.</jats:p>', '10.56238/arev7n3-111', 'https://doi.org/10.56238/arev7n3-111');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('An Improved Deep Learning Based Test Case Prioritization Using Deep Reinforcement Learning', '', 2023, '', '10.22266/ijies2024.0229.64', 'https://doi.org/10.22266/ijies2024.0229.64');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Teacher Professionalism and Its Relationship with Student Learning Achievement in Fiqh Subject at MAS Nurul Haq Rite', 'Abdul Hafid;  Nurmalah', 2025, '<jats:p>This study investigates the relationship between Fiqh teacher professionalism and student learning achievement at MAS Nurul Haq Rite, Ambalawi District, Bima Regency. Teacher professionalism is defined as the expertise, authority, and quality of a Fiqh teacher''s work, encompassing their competence in planning, subject matter mastery, teaching implementation, and assessment skills. Student learning achievement is measured by academic outcomes reflected in grades. Employing a mixed-methods approach combining library research and field research, data was collected through questionnaires administered to randomly selected 10th and 11th-grade students, as well as through observation, interviews, and documentation studies. The collected data was analyzed using the product moment formula and the coefficient of determination to assess the correlation and contribution of teacher professionalism to student learning outcomes. The research findings demonstrate a positive and significant relationship between Fiqh teacher professionalism and student learning achievement at the studied institution. Statistical analysis reveals that teacher professionalism accounts for 50% of the variance in student learning achievement in Fiqh. This indicates that the level of a Fiqh teacher''s professionalism is a substantial determinant of student academic success in this subject, while the remaining 50% of the variance is influenced by other factors not explored in this study. These results underscore the critical role of teacher professionalism in fostering improved learning outcomes in Islamic jurisprudence.</jats:p>', '10.62945/deeplearning.v1i1.210', 'https://doi.org/10.62945/deeplearning.v1i1.210');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Detecting Pneumonia from X-Ray Images using Deep Learning', 'Deep Piyushkumar Patel', 2021, '', '10.21275/sr21324121633', 'https://doi.org/10.21275/sr21324121633');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Seafloor Pipeline Detection With Deep Learning', 'Vemund Sigmundson Schøyen; Narada Dilp Warakagoda; Øivind Midtgaard', 2021, '<jats:p>This paper presents fast, accurate, and automatic methods for detecting seafloor pipelines in multibeam echo sounder data with deep learning. The proposed methods take inspiration from the highly successful ResNet and YOLO deep learning models and tailor them to the idiosyncrasies of the seafloor pipeline detection task.&#x0D; We use the area between lines and Hausdorff line distance functions to accurately evaluate how well methods can localize (pipe)lines. The same functions also show promise as loss functions compared to standard mean squared error, which does not include the regression variables'' geometrical interpretation.&#x0D; The model outperforms the highest likelihood baseline by more than 35% on a region-wise F1-score classification evaluation while being more than eight times more accurate than the baseline in locating pipelines. It is efficient, operating at over eighteen 32-ping image segments per second, which is far beyond real-time requirements.</jats:p>', '10.7557/18.5699', 'https://doi.org/10.7557/18.5699');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Expert Q-learning: Deep Reinforcement Learning with Coarse State Values from Offline Expert Examples', 'Li Meng; Anis Yazidi; Morten Goodwin; Paal Engelstad', 2022, '<jats:p>In this article, we propose a novel algorithm for deep reinforcement learning named Expert Q-learning. Expert Q-learning is inspired by Dueling Q-learning and aims to incorporate semi-supervised learning into reinforcement learning through splitting Q-values into state values and action advantages. We require that an offline expert assesses the value of a state in a coarse manner using three discrete values. An expert network is designed in addition to the Q-network, which updates each time following the regular offline minibatch update whenever the expert example buffer is not empty. Using the board game Othello, we compare our algorithm with the baseline Q-learning algorithm, which is a combination of Double Q-learning and Dueling Q-learning. Our results show that Expert Q-learning is indeed useful and more resistant to the overestimation bias. The baseline Q-learning algorithm exhibits unstable and suboptimal behavior in non-deterministic settings, whereas Expert Q-learning demonstrates more robust performance with higher scores, illustrating that our algorithm is indeed suitable to integrate state values from expert examples into Q-learning.</jats:p>', '10.7557/18.6237', 'https://doi.org/10.7557/18.6237');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Implementation of Deep Learning in Education: Towards Mindful, Meaningful, and Joyful Learning Experiences', 'Lukie Masayu Andayanie; Muhammad Syahriandi Adhantoro; Eko Purnomo; Ganno Tribuana Kurniaji', 2026, '<jats:p>The deep learning approach in education has emerged as a promising pedagogical framework for transforming the learning experience to be more holistic, reflective, and aligned with the needs of the twenty‑first century. This study seeks to conceptually explore how the principles of mindful, meaningful, and joyful learning may be integrated through deep learning–based instructional strategies. The methodology comprises a systematic literature review and a conceptual analysis of pertinent academic publications, research reports, and innovative educational practices. Findings reveal that strategies such as personalized learning, project‑based learning, game‑based learning, and community engagement effectively enhance student engagement, critical thinking skills, and intrinsic motivation. Nonetheless, the implementation of deep learning approaches continues to encounter significant challenges, including educator preparedness, limitations in technological infrastructure, and the misalignment of conventional assessment systems. This article recommends the enactment of progressive policy support, the enhancement of professional capacity among educators, and further empirical research to evaluate the efficacy of deep learning strategies across broader contexts. It is anticipated that these findings will contribute to the advancement of more adaptive, inclusive, and empowering educational policies and practices.</jats:p>', '10.23917/jdl.v1i1.11157', 'https://doi.org/10.23917/jdl.v1i1.11157');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning: Implementation and Impact in Islamic Junior High  Schools', 'Erda Farid Hidayani; Harun Joko Prayitno; Trisakti Handayani', 2026, '<jats:p>This study aims to describe the implementation of deep learning strategies at the secondary level within an Islamic educational setting, specifically at SMP Islam Ar‑Rahmah. A descriptive qualitative approach was employed to examine in depth the teaching–learning processes integrated with Islamic values and the school’s sociocultural context. Data were gathered through participatory observation, in‑depth interviews, and the documentation of instructional materials. The findings reveal that deep learning was effectively realized through Problem‑Based Learning (PBL) and Project‑Based Learning (PjBL) in both the natural science (IPA) and social science (IPS) curricula. Students actively engaged in contextualized projects—such as the Socio Project Board initiative and water‑filtration experiments—which fostered critical thinking, collaborative teamwork, and data‑driven decision‑making competencies. Moreover, the integration of religious programming and boarding‑school activities contributed to the development of intrapersonal and interpersonal skills that align with the core values of Pancasila students. Nevertheless, challenges persist, particularly with respect to instructional design and the availability of teacher training. Consequently, systemic support from educational institutions and policymakers is necessary to bolster the sustainable and meaningful implementation of deep learning in Islamic schools.</jats:p>', '10.23917/jdl.v1i1.11077', 'https://doi.org/10.23917/jdl.v1i1.11077');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Transfer Learning in der Arbeitsplanung/Deep transfer learning in process planning – A concept for applying deep transfer learning in process planning using the example of manufacturing operations selection', 'Marco Hussong; Moritz Glatt; Jan C. Aurich', 2023, '<p>Für die Nutzung von Deep Learning zur Unterstützung der Prozesse innerhalb der Arbeitsplanung wird eine Vielzahl von Daten benötigt. In der industriellen Praxis ist die Aufbereitung solcher Datensätze sehr komplex und mit hohen Aufwand verbunden. Durch die Nutzung von Deep Transfer Learning kann die benötigte Datenmenge reduziert werden. Am Beispiel der Fertigungsvorgangsermittlung wird ein Konzept vorgestellt, das die Anwendung von Deep Transfer Learning innerhalb der Arbeitsplanung ermöglicht. </p>           <p> </p>           <p>A large amount of data is required for the use of deep learning to support process planning. In industrial practice, the preparation of such data sets is very complex and requires a lot of manual effort. By using deep transfer learning, the required amount of data can be reduced. Therefore, using the example of manufacturing operation selection, a concept is introduced that enables the application of deep transfer learning within process planning.</p>', '10.37544/1436-4980-2023-06-16', 'https://doi.org/10.37544/1436-4980-2023-06-16');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Evaluation of learning methods similar to deep learning and device using deep learning for the diagnosis of thyroid nodules', 'Kwak Jin Young; Daham Kim; Kim Youngsook Kim; Eunjung Lee', 2023, '', '10.1530/endoabs.92.op-08-01', 'https://doi.org/10.1530/endoabs.92.op-08-01');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Toward a Theoretical Model of Deep Mathematical Thinking: Integrating Deep Learning and Mathematical Reasoning Frameworks', 'Yoga Tegar Santosa; Muhammad Noor Kholid; Naufal Ishartono; Munaaya Fitriyya; Iwan Junaedi', 2026, '<jats:p>In the context of 21st-century education, deep mathematical thinking is key to developing higher-order cognitive abilities. However, current mathematics learning predominantly focuses on procedural skills rather than conceptual understanding and reflection, often hindering the optimal development of students'' deep mathematical thinking. Therefore, this study aims to develop a theoretical Deep Mathematical Thinking model through the integration of deep learning pedagogical principles and the mathematical thinking framework. Employing a systematic theoretical synthesis approach, the developed model identifies and interconnects core elements of deep learning, such as conceptual connectivity, intrinsic motivation, and metacognition with components of mathematical thinking, including reasoning, generalization, representation, and abstraction. The outcome is a three levels hierarchical Deep Mathematical Thinking model: the foundational level, the applied cognitive level, and the integrative level. This model offers theoretical and practical implications for curriculum design, assessment, and instructional practices. While still conceptual and requiring further empirical validation, the model is flexible and adaptable across diverse educational levels and contexts, positioning it as a potentially robust conceptual framework for developing reflective and meaningful mathematics learning.</jats:p>', '10.23917/jdl.v1i2.11142', 'https://doi.org/10.23917/jdl.v1i2.11142');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Intelligent Learning Systems: A Deep Dive into Architectures, Algorithms, and Applications of  Deep Learning', '', 2025, '', '10.56726/irjmets83343', 'https://doi.org/10.56726/irjmets83343');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep learning and deep transfer learning-based OPM for FMF systems', 'M.A. Amirabadi; M.H. Kahaei; S.A. Nezamalhosseini', 2023, '', '10.1016/j.phycom.2023.102157', 'https://doi.org/10.1016/j.phycom.2023.102157');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning zur  Kariesdiagnostik', 'Norbert Krämer; Roland Frankenberger', 2023, '', '10.1007/s44190-023-0647-4', 'https://doi.org/10.1007/s44190-023-0647-4');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Set-based design using deep learning network', 'Haruo Ishikawa', 2020, '', '10.1299/jsmedsd.2020.30.2401', 'https://doi.org/10.1299/jsmedsd.2020.30.2401');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Object Detection with Deep Learning', 'Yash Bhadiyadra', 2023, '', '10.21275/mr23717204529', 'https://doi.org/10.21275/mr23717204529');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Statement of Retraction: Deep E-Learning RecommendNet: An Acute E-learning Recommendation System with Meta-heuristic-based Hybrid Deep Learning Architecture', '', 2025, '', '10.1080/01969722.2025.2577569', 'https://doi.org/10.1080/01969722.2025.2577569');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Voice Veritas: Fake Voice Detection Using Deep Learning', 'Anju A.; Heshikaa S.; Assmiya J.; Archana D.; S. Muthuselvan; M. Beema Mehraj', 2025, '<jats:p>The rise of deepfake audio technology has sparked serious concerns about the authenticity of voice recordings, driving the need for reliable detection methods. This paper introduces Voice Veritas, a deep learning system designed to detect fake voices using a hybrid Convolutional Neural Network (CNN) and Long Short-Term Memory (LSTM) architecture. By analyzing Mel spectrograms of audio signals, the system uses CNNs to identify spatial patterns in the frequency domain and LSTMs to track temporal changes over time. Trained and tested on the ASVspoof 2019 dataset—a collection of 10,000 real and synthetic audio samples—the model undergoes preprocessing steps such as audio standardization, mel spectrogram conversion, and label encoding. The hybrid CNN-LSTM architecture achieves high accuracy, outperforming traditional methods that rely on manual feature engineering. Experimental results highlight the model’s ability to reliably distinguish genuine from fake audio, even when challenged by diverse spoofing techniques. Key innovations include the seamless integration of CNN and LSTM layers for capturing spatial and temporal details, a streamlined preprocessing workflow, and benchmark performance that sets a new standard in the field. This work addresses gaps in current audio forensics and offers a practical solution for real-world applications. Looking ahead, future research could explore adversarial training to enhance robustness and lightweight models for deployment on edge devices.</jats:p>', '10.64820/aepjmldl.21.41.45.62025', 'https://doi.org/10.64820/aepjmldl.21.41.45.62025');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Medical Imaging Analysis with Deep Learning', 'Brijesh Kannaujiya; Ayan Rajput', 2025, '', '10.21275/sr25617135803', 'https://doi.org/10.21275/sr25617135803');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Convolutional Tables: Deep Learning Without Convolutions', 'Shay Dekel; Yosi Keller; Aharon Bar-Hillel', 2024, '', '10.1109/tnnls.2023.3270402', 'https://doi.org/10.1109/tnnls.2023.3270402');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Revolutionizing Robotics with AI, Machine Learning, and Deep Learning: A Deep Dive into Current Trends and Challenges', 'Premkumar Ganesan', 2024, '', '10.51219/jaimld/premkumar-ganesan/263', 'https://doi.org/10.51219/jaimld/premkumar-ganesan/263');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('A Review on Fraud Detection Using Machine Learning and Deep Learning', 'T Madhavappa Bachala Sathyanarayana', 2024, '', '10.21275/sr24114141555', 'https://doi.org/10.21275/sr24114141555');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Monkeypox Virus Detection Using Deep Learning Methods', 'Bilal Shabbir Qaisar; Sunil Ashraf; M. Mudasar Azeem; Muhammad Ali Shahid; Maham Ali; Mubasher Hussain', 2026, '<jats:p>The fast spread of the recent monkeypox outbreak has become a public health worry in more than 40 nations outside of Africa. Similar to chickenpox and measles, a clinical diagnosis of monkeypox in the early stages might be difficult. A computer-assisted method of detecting monkeypox lesions could be helpful for surveillance and early case identification in areas where confirmatory Polymerase Chain Reaction (PCR) assays are not easily accessible. As long as enough data is available for training, deep-learning techniques help automate the detection of skin lesions. First, we refreshed the “Monkeypox Skin Lesion (MSL) Dataset,” which includes photos of monkeypox, other, and normal skin lesions. To enhance the sample size, we enrich the data and set up a 3-fold cross-validation experiment. Following this, multiple pre-trained deep learning models distinguish between monkeypox, normal, and other disorders. These models are ResNet50V2, Xception, and MobileNetV2. An ensemble model consisting of all three is also created. The best overall accuracy is reached by Xception, at 96.19%, followed by ResNet50V2 (93.33%) and the MobileNetV2 model (86.67%). To propose using a typical fine-tuned architecture for different Deep Learning (DL) models for the detection of MonkeyPox virus, and compare the results. To improve the accuracy of the existing research methods.</jats:p>', '10.64820/aepjmldl.22.10.18.122025', 'https://doi.org/10.64820/aepjmldl.22.10.18.122025');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Implementing Deep Learning Algorithms in Anatomic Pathology Using Open-source Deep Learning Libraries', 'Ewen McAlpine; Pamela Michelow', 2020, '<jats:p>The application of artificial intelligence technologies to anatomic pathology has the potential to transform the practice of pathology, but, despite this, many pathologists are unfamiliar with how these models are created, trained, and evaluated. In addition, many pathologists may feel that they do not possess the necessary skills to allow them to embark on research into this field. This article aims to act as an introductory tutorial to illustrate how to create, train, and evaluate simple artificial learning models (neural networks) on histopathology data sets in the programming language <jats:italic toggle="yes">Python</jats:italic> using the popular freely available, open-source libraries <jats:italic toggle="yes">Keras</jats:italic>, <jats:italic toggle="yes">TensorFlow</jats:italic>, <jats:italic toggle="yes">PyTorch</jats:italic>, and <jats:italic toggle="yes">Detecto</jats:italic>. Furthermore, it aims to introduce pathologists to commonly used terms and concepts used in artificial intelligence.</jats:p>', '10.1097/pap.0000000000000265', 'https://doi.org/10.1097/pap.0000000000000265');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Using Deep Learning Methods to Monitor Non-Observable States in a Building', 'Kristoffer Tangrand; Bernt Bremdal', 2020, '<jats:p>This paper presents results from ongoing research with a goal to use a combination of time series from non-intrusive soft sensors and deep recurrent neural networks to predict room usage at a university campus. Training data was created by collecting measurements from sensors measuring room CO2, humidity, temperature, light, motion and sound, while the labels was created manually by human inspection. Results include analyses of relationships between different sensor data sequences and recommendations for a prototype predictive model using deep recurrent neural networks.</jats:p>', '10.7557/18.5159', 'https://doi.org/10.7557/18.5159');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Visual and Contextual Learning for Deep Learning Education: A Unified Tool for Theory–Practice Integration', 'Itang Enrico Pradana Mahardhika; Harun Joko Prayitno; Indri Indri; Muhammad Ramadhan Fitriyan', 2026, '<jats:p>The rapid advancements in artificial intelligence, particularly in deep learning, demand learning methods that are not only theoretical but also applicative and intuitive. This study aims to design and develop an interactive deep learning instructional tool that integrates real-world case studies and dynamic visualizations to enhance users’ conceptual understanding and practical skills. The research employs a development methodology with a mixed-methods approach, adopting the ADDIE model and iterative formative evaluation based on Tessmer’s framework. The developed tool incorporates three primary case studies: image classification, sentiment analysis, and time-series prediction. Each case study features an interactive interface that allows users to explore data, adjust model parameters, and visualize training processes and results in real time. Formative evaluation results demonstrate the tool’s effectiveness in improving learning engagement, understanding of deep learning model mechanisms, and motivation to explore the topic further. These findings underscore the significance of experiential and visualization-based approaches in cutting-edge technology education while contributing to the development of adaptive AI-based learning media.</jats:p>', '10.23917/jdl.v1i1.11556', 'https://doi.org/10.23917/jdl.v1i1.11556');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('DEEP LEARNING MODELS FOR AUTOMATED MEDICAL IMAGING: ACCURACY, ETHICS, AND DEPLOYMENT CHALLENGES', 'Prasanth Ramaraj; Mohit Mittal', 2025, '', '10.34218/ijaidl_02_01_002', 'https://doi.org/10.34218/ijaidl_02_01_002');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Developing Deep Learning-Based Worksheets to Improve Higher-Order Thinking Skills in Elementary Social Studies', 'Jatmiko Ananda Chosya; Takiddin Takiddin', 2026, '<jats:p>This study aims to develop and evaluate a student worksheet (LKPD) based on deep learning principles to enhance Higher-Order Thinking Skills (HOTS) among fourth-grade students in a madrasah Social Studies context. Employing a Research and Development (R&amp;D) approach with the ADDIE model, the study proceeded through five systematic stages: Analysis, Design, Development, Implementation, and Evaluation. The LKPD was validated by experts in content, language, and media, resulting in an overall validity score of 84.6%, indicating high feasibility for classroom use. In the implementation phase, 30 students participated in pretest and posttest activities. Statistical analysis showed a significant improvement in student learning outcomes, with a t-test significance value of 0.000 and an average N-Gain score of 0.32, classified as moderate. Pedagogical features such as differentiated learning strategies, comic-based apperception, and audio-visual integration through QR codes were embedded in the LKPD to target HOTS domains of analysis, evaluation, and creation. Compared to previous studies, this research extends the application of HOTS-based learning materials into the context of Islamic primary education and demonstrates the pedagogical potential of deep learning in fostering critical and creative thinking. These findings support the broader adoption of multimodal, student-centered instructional designs to meet the demands of 21st-century education.</jats:p>', '10.23917/jdl.v1i1.11156', 'https://doi.org/10.23917/jdl.v1i1.11156');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('LAO SIGN LANGUAGE RECOGNITION USING DEEP LEARNING', 'Phengsavanh Phanthavong; Lathsamy Chidtavong; Phouthone Vongpasith; Chitnavanh Phonekhamma', 2025, '', '10.34218/ijnndl_02_02_002', 'https://doi.org/10.34218/ijnndl_02_02_002');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('COMPARATIVE STUDY OF MACHINE LEARNING AND DEEP  LEARNING METHODS FOR EMOTION RECOGNITION IN TEXTS', 'Zhanna Danilich; Habriiela Leva', 2026, '', '10.52058/2695-1592-2025-11(54)-223-234', 'https://doi.org/10.52058/2695-1592-2025-11(54)-223-234');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Real time waste classification using deep learning and AV: Deep learning and implementation in the frontend', 'Akshat Shrivastava', 2023, '<jats:p>To combat climate change, accurate waste disposal is essential at the point of disposal. Strong greenhouse gases like methane are released into the atmosphere when items that might be recycled or composted are instead dumped in landfills. Current efforts to lessen the disposal of incorrect garbage are often costly, incorrect, and lengthy. In this project, we offer NoWa, an intuitive smartphone app that instantly categorises waste into recyclable or compost for consumers. NoWa uses highly efficient deep learning algorithms, using modern deep learning techniques and models. We have tested several convolution neural network topologies for garbage detection and classification. On the test set, our best model, a multi-layer deep learning residual convoluted neural network, has an accuracy of more than 95%- a number higher than what has ever been achieved in such models.</jats:p>', '10.47611/jsrhs.v12i2.4208', 'https://doi.org/10.47611/jsrhs.v12i2.4208');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Designing Frameworks for Reliability in Deep Learning Systems', 'AYSE ARSLAN', 2022, '<jats:p>There has been a great amount of progress in deep learning models in the last decade. Such models are most accurate when applied to test data drawn from the same distribution as their training set. However, in practice, the data confronting models in real-world settings rarely match the training distribution.  This study explores the use of co-design approaches for developing reliable design frameworks for deep learning systems. It aims to raise awareness on how to develop reliable ML models within the context of recommender systems. While much work needs to be done in this field, the study provides suggestions and practical tips for how to develop reliable ML models such as in the case of recommender systems</jats:p>', '10.47191/etj/v7i10.07', 'https://doi.org/10.47191/etj/v7i10.07');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Automated Classification of Liver Disease Stages and Tumor Detection using Hybrid Deep Learning Techniques', 'G Sharmila; Arthi A.; Keerthana S.; Lakshmi R.', 2025, '<jats:p>Deep Learning (DL), a distinguished branch of Artificial Intelligence and Machine Learning, has emerged as a transformative method for solving complicated troubles throughout numerous domains, specifically in medical imaging. Its capability to automatically analyze hierarchical representations from huge-scale facts makes it distinctly effective for sickness prognosis and class. This venture provides a hybrid DL model that mixes Convolutional Neural Networks (CNNs) and Long Short-Term Memory (LSTM) networks to automate the classification of liver disease levels and hit upon tumors with advanced accuracy. CNNs are used to extract spatial capabilities from CT and MRI scans, efficaciously capturing the structural traits of liver tissues and abnormalities. LSTM networks, then again, are capable of studying temporal dependencies from sequences of photo slices, allowing the version to investigate ailment progression across multiple imaging stages. The integration of CNN and LSTM allows the model to apprehend both spatial and temporal factors of liver diseases, which substantially complements diagnostic overall performance. This hybrid architecture is specially suitable for multiphasic CT and MRI datasets, wherein temporal statistics performs a critical role. The proposed device gives a strong and dependable answer for helping clinicians in early detection, particular staging, and remedy planning of liver issues, contributing to higher affected person effects and healthcare performance.</jats:p>', '10.64820/aepjmldl.21.25.32.62025', 'https://doi.org/10.64820/aepjmldl.21.25.32.62025');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Systematic Review on Machine Learning and Deep Learning Approaches for Mammography Image Classification', '', 2020, '', '10.5373/jardcs/v12i7/20202015', 'https://doi.org/10.5373/jardcs/v12i7/20202015');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Application of Deep Q-learning and double Deep Q-learning algorithms to the task of control an inverted pendulum', ' ; Alla Evseenko; Dmitrii Romannikov;  ', 2020, '<jats:p>Today, such a branch of science as «artificial intelligence» is booming in the world. Systems built on the basis of artificial intelligence methods have the ability to perform functions that are traditionally considered the prerogative of man. Artificial intelligence has a wide range of research areas. One such area is machine learning. This article discusses the algorithms of one of the approaches of machine learning – reinforcement learning (RL), according to which a lot of research and development has been carried out over the past seven years. Development and research on this approach is mainly carried out to solve problems in Atari 2600 games or in other similar ones. In this article, reinforcement training will be applied to one of the dynamic objects – an inverted pendulum. As a model of this object, we consider a model of an inverted pendulum on a cart taken from the Gym library, which contains many models that are used to test and analyze reinforcement learning algorithms. The article describes the implementation and study of two algorithms from this approach, Deep Q-learning and Double Deep Q-learning. As a result, training, testing and training time graphs for each algorithm are presented, on the basis of which it is concluded that it is desirable to use the Double Deep Q-learning algorithm, because the training time is approximately 2 minutes and provides the best control for the model of an inverted pendulum on a cart.</jats:p>', '10.17212/2307-6879-2020-1-2-7-25', 'https://doi.org/10.17212/2307-6879-2020-1-2-7-25');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('EVALUATION OF MACHINE LEARNING AND DEEP LEARNING TECHNIQUES APPLIED IN SCI INJURY', 'Valerio Junior Piana; Fernanda Forbici; Joelias Silva Pinto Junior; Alexandre Leopoldo Gonçalves', 2025, '<jats:p>The application of different technologies from the 4th industrial revolution, such as the use of Machine Learning (ML) and Deep Learning (DL), increasingly permeates different domains of knowledge, ensuring greater efficiency for specialists facing the challenges of their occupations. However, in the medical and physiotherapeutic fields, one of the greatest challenges is the effective treatment of Spinal Cord Injury (SCI), making it essential to implement support systems that are catalyst vectors of the therapeutic process using Artificial Intelligence (AI) techniques, while also taking information security into consideration. Objective: To evaluate different treatment techniques and procedures for SCI that use AI techniques. Methodology: Through a systematic review using the PRISMA-P methodology, reporting a synthesis of the impact of the studies. Results: 168 studies were identified in literature, which, after the application of selection criteria, resulted in 12 (7.14%) eligible references. Conclusion: The studies point to different therapeutic interventions with the application of Brain-Machine Interfaces for use in the healthcare field, bringing challenging approaches to the heterogeneity of computer systems, sensors, and actuators.</jats:p>', '10.18624/e-tech.v18i1.1400', 'https://doi.org/10.18624/e-tech.v18i1.1400');
