INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Facial Emotion Detection using Machine Learning and Deep Learning Algorithms', 'Dr.B. Rebecca; Bathul Spandana; Bingi Swathi', 2025, '', '10.55248/gengpi.6.0425.1663', 'https://doi.org/10.55248/gengpi.6.0425.1663');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Project Based Learning Model to Improve Students'' Critical Thinking Skills in Natural Science Learning at MIS Asy Syafi''iyah Pecangakan', 'Uun Fitrianingsih; Wahidah Rahmawati; Uswatun Hasanah; Uswatun Khasanah; Vina Nur Rosyida', 2025, '<jats:p>The 21st century life is a life without boundaries, globalization, and the exploration of technology is very easy. The digital economy era of the 21st century requires a knowledgeable, skilled, and innovative workforce. Therefore, students must be able to solve problems with superior thinking ability to be ready to plunge into global society. To overcome this challenge, students need to be equipped with 21st century skills that have four main components: digital literacy skills, creative thinking, effective communication skills, and high productivity. In these four components, critical thinking skills are included in the thinking component of creativity. The ability to think critically is very important for students to solve problems that arise with logical reasoning and appropriate solutions. To develop critical thinking skills, it is necessary for teachers to create appropriate learning strategies in schools that contains four pillars of education established by UNESCO: learning to know, learning to do, learning to live together and learning to be. Based on the four pillars, the project based learning model is appropriate to develop student’s critical thinking skills. This is because in the model, students as learning center are given a project-shaped problem and they are required to solve it.</jats:p>', '10.62945/deeplearning.v1i1.206', 'https://doi.org/10.62945/deeplearning.v1i1.206');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Deep Learning Models for Sentiment Analysis', 'Saba Tahir', 2023, '', '10.70729/me23213174020', 'https://doi.org/10.70729/me23213174020');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Cryptocurrency Prediction using Deep Learning', 'Abusufiyan Athani Samarth Kumar', 2023, '', '10.21275/sr23319215511', 'https://doi.org/10.21275/sr23319215511');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Implementation of Game Methods to Increase Students'' Interest and Understanding in Learning Aqidah Akhlak at MIS Mathla''ul Anwar Muruy', 'Yayu Nurajizah; Yani Hidayati', 2025, '<jats:p>This study aims to analyze the effectiveness of game-based methods in enhancing students'' interest and understanding of Aqidah Akhlak learning, particularly in the Asmaul Husna material, in the 3rd grade of MIS Mathla''ul Anwar Muruy.The study of Aqidah Akhlak is often considered less interesting by students, so innovative strategies are needed to enhance their learning motivation.The game method is applied as a solution to create a more interactive and enjoyable learning atmosphere. This study used a quantitative approach with data collection techniques through pre-test, post-test, observation, and questionnaire. Data analysis was conducted using the paired sample t-test statistical test to measure the significance of the increase in student understanding before and after the application of the game method. The results showed a significant increase in students'' understanding after the method was applied, with the average post-test score increasing compared to the pre-test. Observation during the learning process also showed that students were more active, enthusiastic, and easier to remember and understand the meaning of Asmaul Husna. In addition, the questionnaire results revealed that 90% of students felt more interested in learning with the game method than the conventional method. In addition to the impact on academic understanding, the game method also has a positive social contribution. Students are more actively interacting, cooperating, and communicating with friends and teachers during the learning process. Thus, this method not only improves cognitive aspects but also affective aspects in Aqidah Akhlak learning. This study recommends the wider use of game methods in Islamic learning and the development of more innovative game variations so that they can be applied at various levels of education.</jats:p>', '10.62945/deeplearning.v1i1.201', 'https://doi.org/10.62945/deeplearning.v1i1.201');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Comparative Analysis of Deep Learning Techniques', 'Rutika Pawar', 2024, '', '10.21275/sr24127165416', 'https://doi.org/10.21275/sr24127165416');
