INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('NOVEL HUMAN-COMPUTER INTERACTION THROUGH A PRISMOF COMPUTER VISION', 'S. Kalenova; Zh. Duisebekov', 2025, '<jats:p>For the past two decades, the innovative developments inComputer Science have made the crucial beneficial influence on Human –Computer Interaction (HCI) applications. Recent advanced HCI techniques areessential elements to enhance current computer interfaces and facilitate thefundamental user-friendly interaction. It is now becoming possible tocommunicate with computers by using hand gesture, pose recognition, eyetracking, emotion recognition and several other developed progressivetechnologies. This paper investigates the direct contribution of Computer Vision(CV) applications to improving various modes of human-interaction, specializedin different prominent industries, where cumulative list of use cases includessport, healthcare, agriculture, transportation, retail and manufacturing fields. Thecurrent work also explores the future forecast of CV applications for the nextdecade and identifies possible scenarios of research directions.</jats:p>', '10.47344/sdubnts.v54i1.537', 'https://doi.org/10.47344/sdubnts.v54i1.537');
