INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('PatchIndex: exploiting approximate constraints in distributed databases', 'Steffen Kläbe; Kai-Uwe Sattler; Stephan Baumann', 2021, '<jats:title>Abstract</jats:title><jats:p>Cloud data warehouse systems lower the barrier to access data analytics. These applications often lack a database administrator and integrate data from various sources, potentially leading to data not satisfying strict constraints. Automatic schema optimization in self-managing databases is difficult in these environments without prior data cleaning steps. In this paper, we focus on constraint discovery as a subtask of schema optimization. Perfect constraints might not exist in these unclean datasets due to a small set of values violating the constraints. Therefore, we introduce the concept of a generic PatchIndex structure, which handles exceptions to given constraints and enables database systems to define these approximate constraints. We apply the concept to the environment of distributed databases, providing parallel index creation approaches and optimization techniques for parallel queries using PatchIndexes. Furthermore, we describe heuristics for automatic discovery of PatchIndex candidate columns and prove the performance benefit of using PatchIndexes in our evaluation.</jats:p>', '10.1007/s10619-021-07326-1', 'https://doi.org/10.1007/s10619-021-07326-1');
