INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Differential Privacy for Databases', 'Joseph P. Near; Xi He', 2021, '<jats:p>Differential privacy is a promising approach to formalizing privacy—that is, for writing down what privacy means as a mathematical equation. This book is provides overview of differential privacy techniques for answering database-style queries. Within this area, we describe useful algorithms and their applications, and systems and tools that implement them.</jats:p>', '10.1561/1900000066', 'https://doi.org/10.1561/1900000066');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Guest Editor''s Introduction', 'Asuman Dogac', 1999, '', '10.1023/a:1008757110474', 'https://doi.org/10.1023/a:1008757110474');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Guest Editor''s Introduction', 'Athman Bouguettaya', 1999, '', '10.1023/a:1008688724671', 'https://doi.org/10.1023/a:1008688724671');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Massively Parallel Databases and MapReduce Systems', 'Shivnath Babu; Herodotos Herodotou', 2013, '<jats:p>Timely and cost-effective analytics over “big data” has emerged as a key ingredient for success in many businesses, scientific and engineering disciplines, and government endeavors. Web clicks, social media, scientific experiments, and datacenter monitoring are among data sources that generate vast amounts of raw data every day. The need to convert this raw data into useful information has spawned considerable innovation in systems for large-scale data analytics, especially over the last decade. This monograph covers the design principles and core features of systems for analyzing very large datasets using massively-parallel computation and storage techniques on large clusters of nodes. We first discuss how the requirements of data analytics have evolved since the early work on parallel database systems. We then describe some of the major technological innovations that have each spawned a distinct category of systems for data analytics. Each unique system category is described along a number of dimensions including data model and query interface, storage layer, execution engine, query optimization, scheduling, resource management, and fault tolerance. We conclude with a summary of present trends in large-scale data analytics.</jats:p>', '10.1561/1900000036', 'https://doi.org/10.1561/1900000036');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Guest Editors'' Introduction', 'Jeff Naughton; Gerhard Weikum', 1998, '', '10.1023/a:1008697329861', 'https://doi.org/10.1023/a:1008697329861');
