INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('SQL databases v. NoSQL databases', 'Michael Stonebraker', 2010, '<jats:p>             The             <jats:italic>Communications</jats:italic>             Web site, http://cacm.acm.org, features more than a dozen bloggers in the BLOG@CACM community. In each issue of             <jats:italic>Communications</jats:italic>             , we''ll publish excerpts from selected posts.           </jats:p>           <jats:p>             <jats:bold>twitter</jats:bold>           </jats:p>           <jats:p>Follow us on Twitter at http://twitter.com/blogCACM</jats:p>           <jats:p>Michael Stonebraker considers several performance arguments in favor of NoSQL databases---and finds them insufficient.</jats:p>', '10.1145/1721654.1721659', 'https://doi.org/10.1145/1721654.1721659');
