INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Multidisciplinary Databases Outperform Specialized and Comprehensive Databases for Agricultural Literature Coverage', 'Melissa Goertzen', 2019, '<jats:p>A Review of:&#x0D; Ritchie, S. M., Young, L. M., &amp; Sigman, J. (2018). A comparison of selected bibliographic database subject overlap for agricultural information. Issues in Science and Technology Librarianship, 89. http://doi.org/10.5062/F49Z9340&#x0D; Abstract&#x0D; Objective – To determine the most comprehensive database(s) for agricultural literature searching.&#x0D; Design – Data collection and analysis was conducted using a modified version of the bibliography method, overlap analysis, chi square tests, and data visualization methods.&#x0D; Setting – An academic library in the U.S.&#x0D; Subjects – Eight commonly used bibliographic databases, including comprehensive agricultural indexes (AGRICOLA, AGRIS, and CAB Abstracts), specialized databases (BIOSIS Previews and FSTA), and multidisciplinary databases (Google Scholar, Scopus, and Web of Science).&#x0D; Methods – The researchers selected three review articles that represented sub-topics within the field of agriculture. Sources listed in the bibliographies of the three review articles were used to build a bibliographic citation set for analysis.&#x0D; Using a modified version of the bibliography method, 90 citations were randomly selected from the above-mentioned citation set. Researchers then turned to the 8 selected databases and searched for all 90 citations in each platform. Search queries were crafted in two ways: unique title strings in quotation marks and combinations of terms entered into the “title”, “keyword”, “journal source”, and “author” fields. Citations were considered to be covered in a database if the full bibliographic record was located using the above-mentioned search strategy.&#x0D; Next, chi square tests were used to evaluate if the expected number of citations from the sample group were found in each database or if the frequency differed between the eight databases. The overlap analysis method provided numerical representation of the degree of similarity and difference across the eight databases. Finally, data visualizations created in Excel and Gephi enhanced comparisons between the eight databases and highlighted differences that were not obvious based solely on the analysis of numerical data.&#x0D; Main Results – Researchers found that comprehensive databases (AGRICOLA, AGRIS, and CAB Abstracts) were not in fact comprehensive in their coverage of agricultural literature. However, the results suggested that CAB Abstracts was more comprehensive than AGRICOLA or AGRIS, particularly in regard to its coverage of the sub-topics “agronomy” and “meat sciences”. However, coverage of the sub-topic “sustainable diets” lagged behind multidisciplinary databases, which may be explained by the fact that the topic is interdisciplinary in nature. The superior coverage of CAB Abstracts over other comprehensive databases is consistent with findings reported by Kawasaki (2004).&#x0D; The analysis of specialized databases (BIOSIS Previews and FSTA) suggested that citations within the scope of the database were covered very well, while those out of scope were not. For instance, the sub-topics “sustainable diets” and “meat science” are out of scope of the biological sciences and thus, were not well covered in BIOSIS.&#x0D;  The multidisciplinary databases (Google Scholar, Scopus and Web of Science) provided the most comprehensive coverage agricultural literature. All three databases covered most citations included in the data set. However, researchers noted that all three databases provided weak coverage of trade published items, books, or older journals.&#x0D; Conclusion – The study found that multidisciplinary databases provide close to full coverage of agricultural literature. In addition, they provide the best access to content that is interdisciplinary in nature. Specialized and comprehensive databases are recommended when research topics are within the scope of the database. Also, they best support in-depth projects such as bibliographies or comprehensive review articles.</jats:p>', '10.18438/eblip29561', 'https://doi.org/10.18438/eblip29561');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Understanding provenance black boxes', 'Adriane Chapman; H. V. Jagadish', 2010, '', '10.1007/s10619-009-7058-3', 'https://doi.org/10.1007/s10619-009-7058-3');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Guest editors'' introduction', 'Hector Garcia-Molina; H. V. Jagadish', 1993, '', '10.1007/bf01277517', 'https://doi.org/10.1007/bf01277517');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Archaeological Databases and GIS:  Working with Databases', 'Thomas Mafredas; George Malaperdas', 2021, '<jats:p>Digital databases are considered nowadays, necessary for the organization of a recent archeological project. Typically, one of the main issues at the stage of archaeological surface research preparation is the method of recording all the archaeological information that will emerge, which is directly dependent on two factors, the difference of each area in terms of its geomorphology, including the climate and general environmental conditions, and the different approach to the objectives to be achieved by the leading archaeologists. As a consequence of all of this, there is no such thing as a uniquely generated form that can act as a guideline. This paper provides some basic database knowledge as well as a case study with a database example.</jats:p>', '10.24018/compute.2021.1.3.20', 'https://doi.org/10.24018/compute.2021.1.3.20');
