INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Correction: Can cloudlet coordination support cloud computing infrastructure?', 'Abdullah Alsaleh', 2023, '', '10.1186/s13677-023-00393-y', 'https://doi.org/10.1186/s13677-023-00393-y');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Factors Affecting Students'' Intention Toward Mobile Cloud Computing', 'Fatheia Hassan Abdulfattah', 2019, '<p>The adoption of mobile cloud computing (MCC) in education systems still faces several obstacles due to technical, environmental, psychological, and individual issues. Considering numerous advantages associated with the adoption of MCC, this article evaluates the frequency of using MCC by students at King Abdul-Aziz University (KAU) and investigates the factors that influence student intention to use MCC. A survey approach has been used to include 163 students of KAU through a random sampling. Results showed that the attitude towards MCC, perceived ease of use, perceived usefulness, social influence, accessibility of technology, individual characteristics, perceived privacy, and security are all important determinants of intention to use MCC. Findings contribute towards research and practice by revealing crucial factors that impact student intention to adopt mobile cloud computing in developing countries.</p>', '10.4018/ijcac.2019040102', 'https://doi.org/10.4018/ijcac.2019040102');
