INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Load balancing in cloud computing – A hierarchical taxonomical classification', 'Shahbaz Afzal; G. Kavitha', 2019, '<jats:title>Abstract</jats:title><jats:p>Load unbalancing problem is a multi-variant, multi-constraint problem that degrades performance and efficiency of computing resources. Load balancing techniques cater the solution for load unbalancing situation for two undesirable facets- overloading and under-loading. In contempt of the importance of load balancing techniques to the best of our knowledge, there is no comprehensive, extensive, systematic and hierarchical classification about the existing load balancing techniques. Further, the factors that cause load unbalancing problem are neither studied nor considered in the literature. This paper presents a detailed encyclopedic review about the load balancing techniques. The advantages and limitations of existing methods are highlighted with crucial challenges being addressed so as to develop efficient load balancing algorithms in future. The paper also suggests new insights towards load balancing in cloud computing.</jats:p>', '10.1186/s13677-019-0146-7', 'https://doi.org/10.1186/s13677-019-0146-7');
