INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('A status report on IEEE Transactions on Cloud Computing', 'Rajkumar Buyya', 2015, '', '10.1109/tcc.2015.2408391', 'https://doi.org/10.1109/tcc.2015.2408391');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Big data analytics in Cloud computing: an overview', 'Blend Berisha; Endrit Mëziu; Isak Shabani', 2022, '<jats:title>Abstract</jats:title><jats:p>Big Data and Cloud Computing as two mainstream technologies, are at the center of concern in the IT field. Every day a huge amount of data is produced from different sources. This data is so big in size that traditional processing tools are unable to deal with them. Besides being big, this data moves fast and has a lot of variety. Big Data is a concept that deals with storing, processing and analyzing large amounts of data. Cloud computing on the other hand is about offering the infrastructure to enable such processes in a cost-effective and efficient manner. Many sectors, including among others businesses (small or large), healthcare, education, etc. are trying to leverage the power of Big Data. In healthcare, for example, Big Data is being used to reduce costs of treatment, predict outbreaks of pandemics, prevent diseases etc. This paper, presents an overview of Big Data Analytics as a crucial process in many fields and sectors. We start by a brief introduction to the concept of Big Data, the amount of data that is generated on a daily bases, features and characteristics of Big Data. We then delve into Big Data Analytics were we discuss issues such as analytics cycle, analytics benefits and the movement from ETL to ELT paradigm as a result of Big Data analytics in Cloud. As a case study we analyze Google’s BigQuery which is a fully-managed, serverless data warehouse that enables scalable analysis over petabytes of data. As a Platform as a Service (PaaS) supports querying using ANSI SQL. We use the tool to perform different experiments such as average read, average compute, average write, on different sizes of datasets.</jats:p>', '10.1186/s13677-022-00301-w', 'https://doi.org/10.1186/s13677-022-00301-w');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Cloud Computing Roundtable', 'Mazin Yousif; Tom Edsall; Johan Krebbers; Stefan Pappe; Yousef A. Khalidi', 2014, '', '10.1109/mcc.2014.5', 'https://doi.org/10.1109/mcc.2014.5');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Cloud Computing - Segurança e Privacidade da Informação na Nuvem (Cloud Computing - Security and Privacy in the Cloud)', 'António Luís Silva', 2012, '', '10.2139/ssrn.2118225', 'https://doi.org/10.2139/ssrn.2118225');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Cloud Computing Infrastructure and Services', 'Ramasankar Molleti', 2026, '<jats:p>This article surveys the development and state of the art in cloud computing infrastructure and cloud services, and how virtualized computing resources offered over the network have redefined enterprise IT. We drill down into the technical foundations of the three core service models (IaaS, PaaS, and SaaS) and explore the upcoming architectural trends like containerization, serverless computing, and edge computing. The research delineates multi-cloud and hybrid deployment’s response to organizational needs for flexibility, cost-effectiveness, and risk management. We also discuss security frameworks and compliance mechanisms formulated to protect cloud-based assets. The turn towards financial transformation from capital to operating expense paradigms is discussed in light of resource optimization strategies. Finally, we present a framework to evaluate plans for cloud adoption against organizational objectives and technical constraints.</jats:p>', '10.47363/jaicc/icaicc/2025(4)11', 'https://doi.org/10.47363/jaicc/icaicc/2025(4)11');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('IEEE Transactions on Sustainable Computing House Advertisement', '', 2016, '', '10.1109/mcc.2016.7', 'https://doi.org/10.1109/mcc.2016.7');
