INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('A financial brokerage model for cloud computing', 'Owen Rogers; Dave Cliff', 2012, '', '10.1186/2192-113x-1-2', 'https://doi.org/10.1186/2192-113x-1-2');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Cloud Computing &amp; AI Optimization', 'Chandra Lekkala', 2026, '<jats:p>Cloud  computing  has  revolutionized  businesses''  operations,  providing  scalable,  cost-effective,  and  efficient  data  storage,  processing,  and  management  solutions.  Integrating  artificial  intelligence  (AI)  within  cloud  environments  has  further  enhanced  optimization  capabilities,  particularly  in  resource  allocation, security, and operational efficiency. This paper explores the leading cloud platforms, including Amazon Web Services (AWS), Microsoft Azure, and Google Cloud Platform (GCP), detailing their core features, advantages, and applications. Additionally, the study delves into cloud data warehousing, emphasizing Snowflake''s role in enterprise analytics. AI-driven resource optimization is examined through auto-scaling, load balancing, and predictive analytics.  Security  considerations  are  also  discussed,  including  AI-enhanced  threat  detection  and  compliance  measures.  The  paper  concludes  with  an  outlook on the future of cloud computing, highlighting AI''s expanding role in business operations.</jats:p>', '10.47363/jaicc/2026(5)504', 'https://doi.org/10.47363/jaicc/2026(5)504');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Digital Transformation and Cloud Computing', ' ; Sravanthi Mallireddy', 2024, '<jats:p>This paper describes how cloud computing is playing an essential part in revolutionizing the way businesses operate. Using cloud services for commercial purposes can increase scalability, reduce costs, improve communication, and foster innovation.</jats:p>', '10.47363/jaicc/2022(1)e169', 'https://doi.org/10.47363/jaicc/2022(1)e169');
