INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('DeepMPTB: a vaginal microbiome-based deep neural network as artificial intelligence strategy for efficient preterm birth prediction', 'Oshma Chakoory; Vincent Barra; Emmanuelle Rochette; Loïc Blanchon; Vincent Sapin; Etienne Merlin; Maguelonne Pons; Denis Gallot; Sophie Comtet-Marre; Pierre Peyret', 2024, '<jats:title>Abstract</jats:title><jats:p>In recent decades, preterm birth (PTB) has become a significant research focus in the healthcare field, as it is a leading cause of neonatal mortality worldwide. Using five independent study cohorts including 1290 vaginal samples from 561 pregnant women who delivered at term (<jats:italic>n</jats:italic> = 1029) or prematurely (<jats:italic>n</jats:italic> = 261), we analysed vaginal metagenomics data for precise microbiome structure characterization. Then, a deep neural network (DNN) was trained to predict term birth (TB) and PTB with an accuracy of 84.10% and an area under the receiver operating characteristic curve (AUROC) of 0.875 ± 0.11. During a benchmarking process, we demonstrated that our DL model outperformed seven currently used machine learning algorithms. Finally, our results indicate that overall diversity of the vaginal microbiota should be taken in account to predict PTB and not specific species. This artificial-intelligence based strategy should be highly helpful for clinicians in predicting preterm birth risk, allowing personalized assistance to address various health issues. DeepMPTB is open source and free for academic use. It is licensed under a GNU Affero General Public License 3.0 and is available at <jats:ext-link xmlns:xlink="http://www.w3.org/1999/xlink" ext-link-type="uri" xlink:href="https://deepmptb.streamlit.app/">https://deepmptb.streamlit.app/</jats:ext-link>. Source code is available at <jats:ext-link xmlns:xlink="http://www.w3.org/1999/xlink" ext-link-type="uri" xlink:href="https://github.com/oschakoory/DeepMPTB">https://github.com/oschakoory/DeepMPTB</jats:ext-link> and can be easily installed using Docker (<jats:ext-link xmlns:xlink="http://www.w3.org/1999/xlink" ext-link-type="uri" xlink:href="https://www.docker.com/">https://www.docker.com/</jats:ext-link>).</jats:p>', '10.1186/s40364-024-00557-1', 'https://doi.org/10.1186/s40364-024-00557-1');
