INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Towards Artificial Intelligence in Sustainable Environmental Development', 'Hamed Taherdust', 2023, '<jats:p>One of the most significant problems facing humankind now is environmental issues, which have harmed life on the planet. Research has been done continuously to lessen the effects of climate change on the local level and to manage its causes. Due to its indisputable rise in popularity, Artificial Intelligence (AI) will be used in a wide range of businesses and for several causes, such as environmental sustainability. Centers with significant ecological impacts may use AI''s potential to alter the globe as the field expands. This article focuses on industries using AI applications for sustainable environmental development such as biodiversity, energy, water, transportation, air, agriculture, and resilience to extreme events. Next, some limitations are presented. To benefit both current and future generations, environmentally friendly AI should be developed.</jats:p>', '10.37256/aie.4120232503', 'https://doi.org/10.37256/aie.4120232503');
