INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Artificial Intelligence for Artificial Artificial Intelligence', 'Peng Dai; . Mausam; Daniel Weld', 2022, '<jats:p>                Crowdsourcing platforms such as Amazon Mechanical Turk have become popular for a wide variety of human intelligence tasks; however, quality control continues to be a significant challenge. Recently, we propose TurKontrol, a theoretical model based on POMDPs to optimize iterative, crowd-sourced workflows. However, they neither describe how to learn the model parameters, nor show its effectiveness in a real crowd-sourced setting. Learning is challenging due to the scale of the model and noisy data: there are hundreds of thousands of workers with high-variance abilities. This paper presents an end-to-end system that first learns TurKontrol''s POMDP parameters from real Mechanical Turk data, and then applies the model to dynamically optimize live tasks. We validate the model and use it to control a successive-improvement process on Mechanical Turk. By modeling worker accuracy and voting patterns, our system produces significantly superior artifacts compared to those generated through nonadaptive workflows using the same amount of money.            </jats:p>', '10.1609/aaai.v25i1.8096', 'https://doi.org/10.1609/aaai.v25i1.8096');
