INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Data Mining mit Prozessdaten (Data Mining with Process Data)', 'Andreas Schuppert; Rainer Perne', 2005, '<jats:title>Abstract</jats:title>                <jats:p>Durch die zunehmende Komplexität der Produktionsprozesse in innovativen Anwendungsfeldern wird die Prozessanalyse und -Modellierung vor neue Herausforderungen gestellt. Typische Problemfelder sind reaktive Feststoffprozesse, komplexe Polymerisationsprozesse und insbesondere biotechnologische Prozesse. Zur Analyse solcher extrem komplexer Systeme sind spezialisierte Verfahren verfügbar, die unter dem Sammelbegriff „Data Mining“ subsummiert werden. Sie erlauben eine zuverlässige Extraktion auch komplexer Muster mit hohem Informationsgehalt aus unstrukturierten Daten. Die für die Prozessanalyse relevanten softwaretechnischen und methodischen Aspekte des Data Mining werden diskutiert und entsprechende Anwendungsworkflows exemplarisch am Beispiel eines biotechnischen Produktionsprozesses sowie eines Polymerprozesses demonstriert.</jats:p>', '10.1524/auto.53.7.342.66710', 'https://doi.org/10.1524/auto.53.7.342.66710');
