INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('On the Complexity of Mining Quantitative Association Rules', 'Jef Wijsen; Robert Meersman', 1998, '', '10.1023/a:1009755120593', 'https://doi.org/10.1023/a:1009755120593');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('РАЗРАБОТКА ИНФОРМАЦИОННОЙ СИСТЕМЫ ОБРАБОТКИ ДАННЫХ С ИСПОЛЬЗОВАНИЕМ ТЕХНОЛОГИИ DATA MINING', 'Г.Т. Балақаева; Д.К. Даркенбаев; Д.С. Кулачар', 2024, '<jats:p>Мақалада  DataMining  технологиясын  қолдана  отырып,  деректерді  өңдеудің  ақпараттық  жүйесін жобалау және әзірлеу ұсынылған. Деректерді өңдеуде DataMining әдістері: логистикалық регрессия, кездейсоқ орман, шешім ағаштары, тірек векторлары әдісі, жасанды нейронды желі қолданылды және нәтижелері  салыстырыла  талданып  кестеге  салынып  көрсетілді.  Әзірленген  ақпараттық  жүйе құрылымданған,  құрылымданбаған  және  жартылай  құрылымданған  емделуші  азаматтардың деректерін өңдеу арқылы медицина қызметкерлеріне емделуші азаматтардың денсаулығына қатысты нақты болжам жасауға мүмкіндік береді. Машиналық оқыту алгоритмдерін пайдаланылып жобаланған ақпараттық   жүйе,   бірнеше   жекелеген   деректерді   негізге   алып   өңдеу   жұмыстарын жүргізеді.Дерекқорданалдыңғы деректерді алып, оларды талдайды, әрі қарай өңдейді ал жақсы нәтиже көрсеткен алгоритм нәтижесін салыстырып, жақсы нәтиже көрсеткен алгоритм таңдалады. Деректерді өңдеугеарналған  ақпараттық  жүйе  қолданушыларға  нақты  уақыт  режимінде  болжам  нәтижелеріналуға  мүмкіндік  береді.  Авторлар  құрылған  ақпараттық  жүйені  өндіріске  енгізуді  және  әрі  қарай зерттеу жұмыстарын жалғастыруды жоспарлап отыр. Деректерді өңдеуге арналған ақпараттық жүйені білім саласында білім алушылардың білім деңгейлеріне болжамдар жасауда қолдануға болады.</jats:p>                                                                                             <jats:p>В статье представлено проектирование и разработка информационной системы обработки данных с использованием технологии DataMining. При обработке данных использовались методы DataMining: логистическая регрессия, случайный лес, деревья решений, метод опорных векторов, искусственная нейронная сеть, результаты сравнивались, анализировались и представлялись в таблице. Разработанная информационная  система  за  счет  обработки  структурированных,  неструктурированных  и полуструктурированных  данных  пациентов  позволяет  медицинским  работникам  делать  точные прогнозы  относительно состояния  здоровья  пациентов.  Информационная  система,  разработанная  с использованием  алгоритмов  машинногообучения,  выполняет  обработку  на  основе  нескольких отдельных  данных.  Предыдущие  данные  берутся  из  базы  данных,  анализируются,  далее обрабатываются, сравнивается алгоритм с лучшими результатами и выбирается алгоритм с лучшими результатами.  Информационная  система  обработки  данных  позволяет  пользователям  получать результаты  прогнозов  в  режиме  реального  времени.  Авторы  планируют  запустить  созданную информационную  систему  в  производство  и  продолжать  дополнять  исследовательскую  работу  в дальнейшем.  Информационная  система  обработки  данных  может  быть  использована  для прогнозирования уровня знаний обучающихся в сфере образования.</jats:p>                                                     <jats:p>The article presents the design and development of a data processing information system using DataMining technology.  When  processing  the  data,  DataMining  methods  were  used:  logistic  regression,  random  forest, decision  trees,  support  vector  machine,  artificial  neural  network,  the  results  were  compared,  analyzed  and presented  in  a  table.  The developed  information  system,  by  processing  structured,  unstructured  and  semi-structured patient data, allows medical professionals to make accurate predictions regarding the health status of patients. An information system developed using machine learningalgorithms performs processing based on several individual data. Previous data is taken from the database, analyzed, further processed, the algorithm with  the  best  results  is  compared,  and  the  algorithm  with  the  best  results  is  selected.  The  data  processing information  system  allows  users  to  obtain  forecast  results  in  real  time.  The  authors  plan  to  put  the  created information system into production and continue to supplement the research work in the future. An information processing system can be used to predict the level of knowledge of students in the field of education.</jats:p>', '10.51889/2959-5894.2024.85.1.011', 'https://doi.org/10.51889/2959-5894.2024.85.1.011');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Themes in data mining, big data, and crime analytics', 'Giles C. Oatley', 2022, '<jats:title>Abstract</jats:title><jats:p>This article examines the impact of new AI‐related technologies in data mining and big data on important research questions in crime analytics. Because the field is so broad, the review focuses on a selection of the most important topics. Challenges for information management, and in turn law and society, include: AI‐powered predictive policing; big data for legal and adversarial decisions; bias using big data and analytics in profiling and predicting criminality; forecasting crime risk and crime rates; and, regulating AI systems.</jats:p><jats:p>This article is categorized under:<jats:list list-type="simple"><jats:list-item><jats:p>Algorithmic Development &gt; Spatial and Temporal Data Mining</jats:p></jats:list-item><jats:list-item><jats:p>Fundamental Concepts of Data and Knowledge &gt; Big Data Mining</jats:p></jats:list-item><jats:list-item><jats:p>Technologies &gt; Artificial Intelligence</jats:p></jats:list-item><jats:list-item><jats:p>Application Areas &gt; Data Mining Software Tools</jats:p></jats:list-item></jats:list></jats:p>', '10.1002/widm.1432', 'https://doi.org/10.1002/widm.1432');
INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Educational Data Mining in Online Learning: Data Mining Techniques and Algorithms, Factors, Equity and Accessibility Dimensions (A Systematic Literature Review)', 'Imalatul Hidayah; Ririen Kusumawati', 2026, '<jats:p>This Systematic Literature Review (SLR) examines the application of Educational Data Mining (EDM) in online learning from 2015 to 2025 using the PRISMA approach. Thirty-two studies were analyzed to identify the data mining techniques used, the factors analyzed, and the extent to which the literature considers the equity and accessibility dimensions. The review results indicate that EDM is widely applied to predict academic performance, identify learning behavior patterns, detect at-risk students, and analyze the use of learning resources. The dominant techniques include classification, prediction, sequence analysis, process mining, and clustering. However, the equity and accessibility aspects are rarely discussed explicitly most studies only implicitly address accessibility through digital interaction behavior, while social factors related to equity, such as learning readiness, environmental support, and the digital divide, appear in only a small proportion. Furthermore, the variety of data formats and limited course coverage limit the generalizability of the findings. Overall, this study emphasizes the need for stronger integration between educational analytics and the social dimension for EDM to more effectively support equitable distribution of quality and access to online learning.</jats:p>', '10.70609/g-tech.v10i1.8628', 'https://doi.org/10.70609/g-tech.v10i1.8628');
