INSERT INTO publication (title, authors, year, abstract_text, doi, url) VALUES ('Data Mining the Internet Archive Collection', 'Caleb McDaniel', 2020, '<jats:p>The collections of the Internet Archive include many digitized historical sources. Many contain rich bibliographic data in a format called MARC. In this lesson, you''ll learn how to use Python to automate the downloading of large numbers of MARC files from the Internet Archive and the parsing of MARC records for specific information such as authors, places of publication, and dates. The lesson can be applied more generally to other Internet Archive files and to MARC records found elsewhere.</jats:p>', '10.46430/phen0035', 'https://doi.org/10.46430/phen0035');
